import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum Turma {
  INFANTIL = 'Educação Infantil',
  FUNDAMENTAL_1 = 'Ensino Fundamental I',
  FUNDAMENTAL_2 = 'Ensino Fundamental II',
  ENSINO_MEDIO = 'Ensino Médio',
  EJA = 'EJA (Educação de Jovens e Adultos)',
  UNIVERSITARIO = 'Universitário',
  OUTROS = 'Outros'
}

export interface TimeSlot {
  start: string;
  end: string;
}

export interface BookingData {
  date: Date;
  slot: TimeSlot;
  responsibleName: string;
  institutionName: string;
  email: string;
  turma: Turma;
  quantity: number;
  objective: string;
}

export interface Holiday {
  date: string; // ISO format YYYY-MM-DD
  name: string;
}

import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const generateObjectiveSuggestion = async (turma: string, institution: string) => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Sugira um objetivo sucinto e pedagógico para uma visita guiada de uma turma de ${turma} da instituição ${institution} a uma biblioteca municipal. Foque em incentivo à leitura e conhecimento do espaço público.`,
      config: {
        temperature: 0.7,
      }
    });
    return response.text || "Incentivar o hábito da leitura e apresentar o acervo da biblioteca.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Incentivar o hábito da leitura e apresentar o acervo da biblioteca.";
  }
};

import React, { useState } from 'react';
import { 
  format, 
  addMonths, 
  subMonths, 
  startOfMonth, 
  endOfMonth, 
  startOfWeek, 
  endOfWeek, 
  isSameMonth, 
  isSameDay, 
  addDays, 
  isWeekend, 
  isBefore, 
  startOfToday,
  parseISO
} from 'date-fns';
import { ptBR } from 'date-fns/locale';
import { ChevronLeft, ChevronRight, Info } from 'lucide-react';
import { BRAZILIAN_HOLIDAYS } from '../constants';

interface CalendarProps {
  onSelectDate: (date: Date) => void;
  selectedDate: Date | null;
}

const Calendar: React.FC<CalendarProps> = ({ onSelectDate, selectedDate }) => {
  const [currentMonth, setCurrentMonth] = useState(new Date());
  const today = startOfToday();

  const nextMonth = () => setCurrentMonth(addMonths(currentMonth, 1));
  const prevMonth = () => setCurrentMonth(subMonths(currentMonth, 1));

  const isHoliday = (date: Date) => {
    const dateStr = format(date, 'yyyy-MM-dd');
    return BRAZILIAN_HOLIDAYS.some(h => h.date === dateStr);
  };

  const getHolidayName = (date: Date) => {
    const dateStr = format(date, 'yyyy-MM-dd');
    return BRAZILIAN_HOLIDAYS.find(h => h.date === dateStr)?.name;
  };

  const renderHeader = () => {
    return (
      <div className="flex items-center justify-between mb-6">
        <h2 className="text-2xl font-bold text-slate-800 capitalize">
          {format(currentMonth, 'MMMM yyyy', { locale: ptBR })}
        </h2>
        <div className="flex space-x-2">
          <button
            onClick={prevMonth}
            className="p-2 hover:bg-slate-200 rounded-full transition-colors"
            title="Mês Anterior"
          >
            <ChevronLeft size={24} />
          </button>
          <button
            onClick={nextMonth}
            className="p-2 hover:bg-slate-200 rounded-full transition-colors"
            title="Próximo Mês"
          >
            <ChevronRight size={24} />
          </button>
        </div>
      </div>
    );
  };

  const renderDays = () => {
    const days = ['Dom', 'Seg', 'Ter', 'Qua', 'Qui', 'Sex', 'Sáb'];
    return (
      <div className="grid grid-cols-7 mb-2">
        {days.map((day, index) => (
          <div key={index} className="text-center text-xs font-bold text-slate-400 uppercase tracking-wider">
            {day}
          </div>
        ))}
      </div>
    );
  };

  const renderCells = () => {
    const monthStart = startOfMonth(currentMonth);
    const monthEnd = endOfMonth(monthStart);
    const startDate = startOfWeek(monthStart);
    const endDate = endOfWeek(monthEnd);

    const rows = [];
    let days = [];
    let day = startDate;

    while (day <= endDate) {
      for (let i = 0; i < 7; i++) {
        const formattedDate = format(day, 'd');
        const cloneDay = day;
        const isDisabled = isWeekend(day) || isHoliday(day) || isBefore(day, today);
        const holidayName = getHolidayName(day);

        days.push(
          <div
            key={day.toString()}
            className={`
              relative h-24 sm:h-32 border-t border-l border-slate-100 p-2 cursor-pointer transition-all
              ${!isSameMonth(day, monthStart) ? 'bg-slate-50 text-slate-300 pointer-events-none' : ''}
              ${isDisabled ? 'bg-slate-50 text-slate-400 cursor-not-allowed' : 'hover:bg-blue-50'}
              ${selectedDate && isSameDay(day, selectedDate) ? 'bg-blue-100 ring-2 ring-blue-500 z-10' : ''}
            `}
            onClick={() => !isDisabled && onSelectDate(cloneDay)}
          >
            <span className={`text-sm font-semibold ${isSameDay(day, today) ? 'text-blue-600 bg-blue-50 px-2 py-1 rounded-md' : ''}`}>
              {formattedDate}
            </span>
            {holidayName && (
              <div className="mt-1 text-[10px] sm:text-xs text-red-500 font-medium leading-tight">
                {holidayName}
              </div>
            )}
            {isDisabled && isSameMonth(day, monthStart) && !holidayName && !isWeekend(day) && (
              <div className="mt-1 text-[10px] text-slate-400">Indisponível</div>
            )}
            {isWeekend(day) && isSameMonth(day, monthStart) && (
              <div className="mt-1 text-[10px] text-slate-400">Fechado</div>
            )}
          </div>
        );
        day = addDays(day, 1);
      }
      rows.push(
        <div className="grid grid-cols-7 border-r border-b border-slate-100" key={day.toString()}>
          {days}
        </div>
      );
      days = [];
    }
    return <div className="bg-white rounded-xl shadow-sm overflow-hidden border border-slate-200">{rows}</div>;
  };

  return (
    <div className="w-full max-w-5xl mx-auto p-4 sm:p-6 bg-white rounded-2xl shadow-lg border border-slate-200">
      <div className="mb-4 flex items-center text-sm text-slate-500 bg-blue-50 p-3 rounded-lg">
        <Info className="mr-2 text-blue-500 flex-shrink-0" size={18} />
        <p>Selecione uma data disponível (dias úteis não feriados) para ver os horários de visita.</p>
      </div>
      {renderHeader()}
      {renderDays()}
      {renderCells()}
    </div>
  );
};

export default Calendar;

import React, { useState, useEffect } from 'react';
import { format } from 'date-fns';
import { ptBR } from 'date-fns/locale';
import { X, Clock, Users, GraduationCap, Building2, User, Mail, FileText, Sparkles, CheckCircle2 } from 'lucide-react';
import { TIME_SLOTS, TURMAS } from '../constants';
import { TimeSlot, Turma, BookingData } from '../types';
import { generateObjectiveSuggestion } from '../services/geminiService';

interface BookingDialogProps {
  date: Date;
  onClose: () => void;
  onComplete: (data: BookingData) => void;
}

const BookingDialog: React.FC<BookingDialogProps> = ({ date, onClose, onComplete }) => {
  const [step, setStep] = useState<'slot' | 'form' | 'success'>('slot');
  const [selectedSlot, setSelectedSlot] = useState<TimeSlot | null>(null);
  const [formData, setFormData] = useState({
    responsibleName: '',
    institutionName: '',
    email: '',
    turma: Turma.INFANTIL,
    quantity: 20,
    objective: ''
  });
  const [isGenerating, setIsGenerating] = useState(false);

  const handleSlotSelect = (slot: TimeSlot) => {
    setSelectedSlot(slot);
    setStep('form');
  };

  const handleSuggestObjective = async () => {
    if (!formData.institutionName) {
      alert("Por favor, informe o nome da instituição primeiro.");
      return;
    }
    setIsGenerating(true);
    const suggestion = await generateObjectiveSuggestion(formData.turma, formData.institutionName);
    setFormData(prev => ({ ...prev, objective: suggestion }));
    setIsGenerating(false);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedSlot) return;

    onComplete({
      date,
      slot: selectedSlot,
      ...formData
    });
    setStep('success');
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
      <div className="bg-white w-full max-w-2xl rounded-2xl shadow-2xl overflow-hidden max-h-[90vh] flex flex-col">
        {/* Header */}
        <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-white sticky top-0 z-10">
          <div>
            <h3 className="text-xl font-bold text-slate-800">
              Agendamento para {format(date, "dd 'de' MMMM", { locale: ptBR })}
            </h3>
            {selectedSlot && (
              <p className="text-blue-600 font-medium text-sm flex items-center mt-1">
                <Clock size={14} className="mr-1" /> {selectedSlot.start} às {selectedSlot.end}
              </p>
            )}
          </div>
          <button onClick={onClose} className="p-2 hover:bg-slate-100 rounded-full transition-colors text-slate-400">
            <X size={24} />
          </button>
        </div>

        <div className="overflow-y-auto p-6">
          {step === 'slot' && (
            <div className="space-y-4">
              <h4 className="text-lg font-semibold text-slate-700 mb-4">Escolha um horário disponível:</h4>
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                {TIME_SLOTS.map((slot, idx) => (
                  <button
                    key={idx}
                    onClick={() => handleSlotSelect(slot)}
                    className="flex items-center justify-between p-4 border border-slate-200 rounded-xl hover:border-blue-500 hover:bg-blue-50 transition-all text-left group"
                  >
                    <div className="flex items-center">
                      <div className="w-10 h-10 bg-blue-100 text-blue-600 rounded-full flex items-center justify-center mr-3 group-hover:bg-blue-600 group-hover:text-white transition-colors">
                        <Clock size={18} />
                      </div>
                      <span className="font-semibold text-slate-700">{slot.start} - {slot.end}</span>
                    </div>
                    <span className="text-xs font-bold text-slate-400 uppercase tracking-tighter">Disponível</span>
                  </button>
                ))}
              </div>
            </div>
          )}

          {step === 'form' && (
            <form onSubmit={handleSubmit} className="space-y-6">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-sm font-semibold text-slate-700 flex items-center">
                    <User size={16} className="mr-1" /> Nome do Responsável
                  </label>
                  <input
                    required
                    type="text"
                    value={formData.responsibleName}
                    onChange={e => setFormData(prev => ({ ...prev, responsibleName: e.target.value }))}
                    className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition-all"
                    placeholder="Nome completo"
                  />
                </div>

                <div className="space-y-2">
                  <label className="text-sm font-semibold text-slate-700 flex items-center">
                    <Building2 size={16} className="mr-1" /> Nome da Instituição
                  </label>
                  <input
                    required
                    type="text"
                    value={formData.institutionName}
                    onChange={e => setFormData(prev => ({ ...prev, institutionName: e.target.value }))}
                    className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition-all"
                    placeholder="Escola, Faculdade, ONG..."
                  />
                </div>

                <div className="space-y-2">
                  <label className="text-sm font-semibold text-slate-700 flex items-center">
                    <Mail size={16} className="mr-1" /> E-mail para confirmação
                  </label>
                  <input
                    required
                    type="email"
                    value={formData.email}
                    onChange={e => setFormData(prev => ({ ...prev, email: e.target.value }))}
                    className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none transition-all"
                    placeholder="email@exemplo.com"
                  />
                </div>

                <div className="space-y-2">
                  <label className="text-sm font-semibold text-slate-700 flex items-center">
                    <GraduationCap size={16} className="mr-1" /> Selecione a Turma
                  </label>
                  <select
                    value={formData.turma}
                    onChange={e => setFormData(prev => ({ ...prev, turma: e.target.value as Turma }))}
                    className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none transition-all bg-white"
                  >
                    {TURMAS.map(t => <option key={t} value={t}>{t}</option>)}
                  </select>
                </div>

                <div className="space-y-2">
                  <label className="text-sm font-semibold text-slate-700 flex items-center">
                    <Users size={16} className="mr-1" /> Qtd. Pessoas (Máx: 40)
                  </label>
                  <input
                    required
                    type="number"
                    min="1"
                    max="40"
                    value={formData.quantity}
                    onChange={e => setFormData(prev => ({ ...prev, quantity: parseInt(e.target.value) || 0 }))}
                    className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none transition-all"
                  />
                </div>
              </div>

              <div className="space-y-2">
                <div className="flex justify-between items-center">
                  <label className="text-sm font-semibold text-slate-700 flex items-center">
                    <FileText size={16} className="mr-1" /> Objetivo da Visita
                  </label>
                  <button
                    type="button"
                    onClick={handleSuggestObjective}
                    disabled={isGenerating}
                    className="text-xs font-bold text-blue-600 flex items-center hover:text-blue-700 bg-blue-50 px-2 py-1 rounded-md transition-colors disabled:opacity-50"
                  >
                    <Sparkles size={12} className="mr-1" /> {isGenerating ? 'Gerando...' : 'Sugerir com IA'}
                  </button>
                </div>
                <textarea
                  required
                  rows={3}
                  value={formData.objective}
                  onChange={e => setFormData(prev => ({ ...prev, objective: e.target.value }))}
                  className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none transition-all resize-none"
                  placeholder="Descreva de forma suscinta o objetivo pedagógico ou cultural da visita."
                />
              </div>

              <div className="flex space-x-3 pt-4 border-t border-slate-100">
                <button
                  type="button"
                  onClick={() => setStep('slot')}
                  className="flex-1 px-6 py-3 border border-slate-200 text-slate-600 font-bold rounded-xl hover:bg-slate-50 transition-colors"
                >
                  Voltar
                </button>
                <button
                  type="submit"
                  className="flex-[2] px-6 py-3 bg-blue-600 text-white font-bold rounded-xl hover:bg-blue-700 shadow-lg shadow-blue-200 transition-all active:scale-95"
                >
                  Confirmar Agendamento
                </button>
              </div>
            </form>
          )}

          {step === 'success' && (
            <div className="flex flex-col items-center justify-center py-10 text-center space-y-4">
              <div className="w-20 h-20 bg-green-100 text-green-600 rounded-full flex items-center justify-center animate-bounce">
                <CheckCircle2 size={48} />
              </div>
              <h3 className="text-2xl font-bold text-slate-800">Agendamento Realizado!</h3>
              <p className="text-slate-500 max-w-sm">
                Enviamos um e-mail de confirmação para <strong>{formData.email}</strong>. Por favor, apresente o e-mail no dia da visita.
              </p>
              <button
                onClick={onClose}
                className="mt-6 px-8 py-3 bg-slate-800 text-white font-bold rounded-xl hover:bg-slate-900 transition-all"
              >
                Concluir
              </button>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default BookingDialog;

