import React, { useState } from 'react';
import { 
  format, 
  addMonths, 
  subMonths, 
  startOfMonth, 
  endOfMonth, 
  startOfWeek, 
  endOfWeek, 
  isSameMonth, 
  isSameDay, 
  addDays, 
  isWeekend, 
  isBefore, 
  startOfToday
} from 'date-fns';
import { ptBR } from 'date-fns/locale';
import { ChevronLeft, ChevronRight, Info, Calendar as CalendarIcon } from 'lucide-react';
import { BRAZILIAN_HOLIDAYS } from '../constants';

interface CalendarProps {
  onSelectDate: (date: Date) => void;
  selectedDate: Date | null;
}

const Calendar: React.FC<CalendarProps> = ({ onSelectDate, selectedDate }) => {
  const [currentMonth, setCurrentMonth] = useState(new Date());
  const today = startOfToday();

  const nextMonth = () => setCurrentMonth(addMonths(currentMonth, 1));
  const prevMonth = () => setCurrentMonth(subMonths(currentMonth, 1));

  const isHoliday = (date: Date) => {
    const dateStr = format(date, 'yyyy-MM-dd');
    return BRAZILIAN_HOLIDAYS.some(h => h.date === dateStr);
  };

  const getHolidayName = (date: Date) => {
    const dateStr = format(date, 'yyyy-MM-dd');
    return BRAZILIAN_HOLIDAYS.find(h => h.date === dateStr)?.name;
  };

  const renderHeader = () => {
    return (
      <div className="flex items-center justify-between p-6">
        <div className="flex flex-col">
          <h2 className="text-3xl font-black text-slate-800 capitalize tracking-tighter">
            {format(currentMonth, 'MMMM', { locale: ptBR })}
            <span className="text-slate-300 font-light ml-2">{format(currentMonth, 'yyyy')}</span>
          </h2>
        </div>
        <div className="flex bg-slate-50 p-1.5 rounded-2xl border border-slate-100">
          <button
            onClick={prevMonth}
            className="p-3 hover:bg-white hover:shadow-sm text-slate-400 hover:text-[#800000] rounded-xl transition-all"
          >
            <ChevronLeft size={20} />
          </button>
          <button
            onClick={nextMonth}
            className="p-3 hover:bg-white hover:shadow-sm text-slate-400 hover:text-[#800000] rounded-xl transition-all"
          >
            <ChevronRight size={20} />
          </button>
        </div>
      </div>
    );
  };

  const renderDays = () => {
    const days = ['Dom', 'Seg', 'Ter', 'Qua', 'Qui', 'Sex', 'Sáb'];
    return (
      <div className="grid grid-cols-7 mb-4 px-6">
        {days.map((day, index) => (
          <div key={index} className="text-center text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">
            {day}
          </div>
        ))}
      </div>
    );
  };

  const renderCells = () => {
    const monthStart = startOfMonth(currentMonth);
    const monthEnd = endOfMonth(monthStart);
    const startDate = startOfWeek(monthStart);
    const endDate = endOfWeek(monthEnd);

    const rows = [];
    let days = [];
    let day = startDate;

    while (day <= endDate) {
      for (let i = 0; i < 7; i++) {
        const formattedDate = format(day, 'd');
        const cloneDay = day;
        const holiday = isHoliday(day);
        const weekend = isWeekend(day);
        const past = isBefore(day, today) && !isSameDay(day, today);
        const isDisabled = weekend || holiday || past;
        const isCurrentDay = isSameDay(day, today);
        const isSelected = selectedDate && isSameDay(day, selectedDate);
        const outside = !isSameMonth(day, monthStart);

        days.push(
          <div
            key={day.toString()}
            className={`
              relative h-20 sm:h-28 flex flex-col items-center justify-start pt-3 border-t border-slate-50 transition-all group
              ${outside ? 'opacity-0 pointer-events-none' : ''}
              ${isDisabled ? 'cursor-not-allowed text-slate-300' : 'cursor-pointer hover:bg-red-50/50'}
              ${isSelected ? 'bg-red-50/80 !border-t-[#800000]' : ''}
            `}
            onClick={() => !isDisabled && onSelectDate(cloneDay)}
          >
            <span className={`
              text-sm font-bold w-8 h-8 flex items-center justify-center rounded-full transition-all
              ${isCurrentDay ? 'bg-[#800000] text-white shadow-lg shadow-red-900/30' : ''}
              ${isSelected ? 'scale-110' : ''}
              ${isDisabled && !isCurrentDay ? 'text-slate-200' : ''}
            `}>
              {formattedDate}
            </span>

            {holiday && !outside && (
              <div className="mt-2 text-[8px] font-black text-red-600 uppercase px-2 text-center leading-none">
                {getHolidayName(day)}
              </div>
            )}

            {!isDisabled && !isSelected && !outside && (
              <div className="mt-auto mb-2 w-1 h-1 bg-green-400 rounded-full opacity-0 group-hover:opacity-100 transition-opacity"></div>
            )}

            {isSelected && (
              <div className="mt-auto mb-2 text-[9px] font-black text-[#800000] uppercase tracking-tighter">Selecionado</div>
            )}
          </div>
        );
        day = addDays(day, 1);
      }
      rows.push(
        <div className="grid grid-cols-7" key={day.toString()}>
          {days}
        </div>
      );
      days = [];
    }
    return <div className="bg-white rounded-b-[2.5rem] overflow-hidden">{rows}</div>;
  };

  return (
    <div className="w-full">
      {renderHeader()}
      {renderDays()}
      {renderCells()}
      <div className="p-6 bg-slate-50/50 rounded-b-[2.5rem] flex flex-wrap gap-6 text-[10px] font-bold uppercase tracking-widest text-slate-400 border-t border-slate-100">
        <div className="flex items-center"><span className="w-2 h-2 bg-[#800000] rounded-full mr-2"></span> Hoje</div>
        <div className="flex items-center"><span className="w-2 h-2 bg-green-400 rounded-full mr-2"></span> Disponível</div>
        <div className="flex items-center"><span className="w-2 h-2 bg-slate-200 rounded-full mr-2"></span> Indisponível</div>
      </div>
    </div>
  );
};

export default Calendar;

