import React, { useState, useEffect } from 'react';
import Calendar from './components/Calendar';
import BookingDialog from './components/BookingDialog';
import { BookingData } from './types';
import { BookOpen, MapPin, Mail, Sparkles, Clock, Users, Loader2, AlertCircle } from 'lucide-react';
import { supabase } from './services/supabase';

const App: React.FC = () => {
  const [selectedDate, setSelectedDate] = useState<Date | null>(null);
  const [showDialog, setShowDialog] = useState(false);
  const [allBookings, setAllBookings] = useState<BookingData[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  // Buscar agendamentos do Supabase
  const fetchBookings = async () => {
    setIsLoading(true);
    setError(null);
    try {
      const { data, error: supabaseError } = await supabase
        .from('bookings')
        .select('*');

      if (supabaseError) {
        console.error("Erro bruto do Supabase:", supabaseError);

        // Se houver erro de "tabela não encontrada" (Código 42P01 no PostgreSQL)
        if (supabaseError.code === '42P01') {
          throw new Error("A tabela 'bookings' não foi encontrada. Você precisa criá-la no SQL Editor do Supabase.");
        }

        // Lança a mensagem de erro vinda do Supabase ou um fallback
        throw new Error(supabaseError.message || "Falha na comunicação com o banco de dados.");
      }

      if (data) {
        const formatted = data.map((b: any) => ({
          ...b,
          date: new Date(b.date),
          slot: { start: b.slot_start, end: b.slot_end },
          responsibleName: b.responsible_name,
          institutionName: b.institution_name,
        }));
        setAllBookings(formatted);
      }
    } catch (e: any) {
      // Captura a mensagem do erro lançado acima
      const errorMsg = e.message || "Erro inesperado ao carregar dados.";
      setError(errorMsg);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    fetchBookings();
  }, []);

  const handleDateSelect = (date: Date) => {
    setSelectedDate(date);
    setShowDialog(true);
  };

  const handleBookingComplete = async (data: BookingData) => {
    setAllBookings(prev => [...prev, data]);
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      {/* Header / Navbar */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-40">
        <div className="max-w-7xl mx-auto px-4 h-20 flex items-center justify-between">
          <div className="flex items-center space-x-3">
            <div className="bg-[#800000] p-2.5 rounded-lg shadow-md shadow-red-900/20">
              <BookOpen className="text-white" size={24} />
            </div>
            <div className="flex flex-col">
              <h1 className="text-lg font-bold text-[#800000] tracking-tight leading-none uppercase">Biblioteca Municipal de Sobral</h1>
              <span className="text-xs font-medium text-slate-500 uppercase tracking-widest">Lustosa da Costa</span>
            </div>
          </div>
          <nav className="flex space-x-6 text-sm font-semibold text-slate-500">
            <a href="#" className="hover:text-[#800000] transition-colors">Início</a>
          </nav>
        </div>
      </header>

      {/* Hero Section */}
      <section className="bg-white border-b border-slate-200 py-12 md:py-16">
        <div className="max-w-5xl mx-auto px-4 text-center space-y-6">
          <div className="inline-flex items-center px-4 py-1.5 bg-[#800000]/10 text-[#800000] rounded-full text-xs font-bold uppercase tracking-wider mb-2">
            <Sparkles size={14} className="mr-1.5" /> Agendamento de Visitas
          </div>
          <h2 className="text-4xl md:text-5xl font-extrabold text-slate-900 tracking-tight leading-tight">
            Explore a Cultura e o Conhecimento em nossa Biblioteca
          </h2>
          <p className="text-lg text-slate-600 max-w-2xl mx-auto">
            Reserve agora uma visita guiada para sua instituição e descubra o rico acervo da Biblioteca Municipal de Sobral Lustosa da Costa.
          </p>
        </div>
      </section>

      {/* Calendar Section */}
      <main className="flex-grow py-12 px-4">
        <div className="max-w-7xl mx-auto grid grid-cols-1 lg:grid-cols-12 gap-8">

          {/* Sidebar Info */}
          <div className="lg:col-span-3 space-y-6">
            <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm space-y-6">
              <h3 className="font-bold text-slate-800 border-b border-slate-100 pb-3">Informações Úteis</h3>

              <div className="flex items-start space-x-3">
                <div className="p-2 bg-slate-50 rounded-lg text-[#800000]">
                  <Clock size={18} />
                </div>
                <div>
                  <p className="text-sm font-bold text-slate-800">Horário de Visita</p>
                  <p className="text-xs text-slate-500">Seg a Sex: 08:00 - 16:00</p>
                </div>
              </div>

              <div className="flex items-start space-x-3">
                <div className="p-2 bg-slate-50 rounded-lg text-[#800000]">
                  <MapPin size={18} />
                </div>
                <div>
                  <p className="text-sm font-bold text-slate-800">Localização</p>
                  <p className="text-xs text-slate-500 leading-relaxed">R. Randal Pompeu, S/N - Centro,<br/>Sobral - CE, 62010-460</p>
                </div>
              </div>

              <div className="flex items-start space-x-3">
                <div className="p-2 bg-slate-50 rounded-lg text-[#800000]">
                  <Users size={18} />
