                  Tentar novamente
                </button>
              </div>
            )}

            <div className="bg-gradient-to-br from-[#800000] to-[#5a0000] p-6 rounded-2xl shadow-lg text-white">
              <h3 className="font-bold text-lg mb-2">Suporte</h3>
              <p className="text-sm text-red-100 mb-4">Dúvidas sobre o agendamento ou visitas personalizadas?</p>
