            {isLoading && (
              <div className="absolute inset-0 bg-white/60 backdrop-blur-[2px] z-20 flex items-center justify-center rounded-2xl">
                <div className="flex flex-col items-center">
                  <Loader2 className="animate-spin text-[#800000] mb-2" size={40} />
                  <p className="text-sm font-bold text-slate-600">Conectando ao banco...</p>
                </div>
              </div>
            )}
            <Calendar onSelectDate={handleDateSelect} selectedDate={selectedDate} />
          </div>
        </div>
      </main>

      {/* Footer */}
      <footer className="bg-[#800000] text-red-50 py-12 mt-auto shadow-[0_-10px_30px_-15px_rgba(0,0,0,0.3)]">
        <div className="max-w-7xl mx-auto px-4 grid grid-cols-1 md:grid-cols-4 gap-8">
          <div className="col-span-1 md:col-span-2">
            <div className="flex items-center space-x-3 mb-4">
              <div className="bg-white p-1.5 rounded-lg">
                <BookOpen className="text-[#800000]" size={24} />
              </div>
              <div className="flex flex-col">
                <span className="text-lg font-bold text-white tracking-tight leading-none">BIBLIOTECA DE SOBRAL</span>
                <span className="text-[10px] text-red-200 uppercase font-medium">Lustosa da Costa</span>
              </div>
            </div>
            <p className="max-w-md text-sm leading-relaxed text-red-100 opacity-90">
              Equipamento cultural da Secretaria Municipal de Educação da Prefeitura de Sobral, focado na democratização do acesso à leitura e na preservação da memória local.
