        />
      )}
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { format, isSameDay } from 'date-fns';
import { ptBR } from 'date-fns/locale';
import { X, Clock, Users, GraduationCap, Building2, User, Mail, FileText, Sparkles, BookOpen, Calendar as CalendarIcon, CheckCircle2, Loader2, Download, Printer, Send } from 'lucide-react';
import { TIME_SLOTS, TURMAS } from '../constants';
import { TimeSlot, Turma, BookingData } from '../types';
import { generateObjectiveSuggestion } from '../services/geminiService';
import { supabase } from '../services/supabase';

interface BookingDialogProps {
  date: Date;
  existingBookings: BookingData[];
  onClose: () => void;
  onComplete: (data: BookingData) => void;
}

const BookingDialog: React.FC<BookingDialogProps> = ({ date, existingBookings, onClose, onComplete }) => {
  const [step, setStep] = useState<'slot' | 'form' | 'success'>('slot');
  const [selectedSlot, setSelectedSlot] = useState<TimeSlot | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [formData, setFormData] = useState({
    responsibleName: '',
    institutionName: '',
    email: '',
    turma: Turma.INFANTIL,
    quantity: '' as unknown as number,
    objective: ''
  });
  const [isGenerating, setIsGenerating] = useState(false);

  const isSlotTaken = (slot: TimeSlot) => {
    return existingBookings.some(b => 
      isSameDay(new Date(b.date), date) && 
      b.slot.start === slot.start && 
      b.slot.end === slot.end
    );
  };

  const handleSlotSelect = (slot: TimeSlot) => {
    if (isSlotTaken(slot)) return;
    setSelectedSlot(slot);
    setStep('form');
  };

  const handleSuggestObjective = async () => {
    if (!formData.institutionName) {
      alert("Por favor, informe o nome da instituição primeiro.");
      return;
    }
    setIsGenerating(true);
    const suggestion = await generateObjectiveSuggestion(formData.turma, formData.institutionName);
    setFormData(prev => ({ ...prev, objective: suggestion }));
    setIsGenerating(false);
  };

  const generateICS = () => {
    if (!selectedSlot) return;
    const dateFormatted = format(date, 'yyyyMMdd');
    const startTime = selectedSlot.start.replace(':', '') + '00';
    const endTime = selectedSlot.end.replace(':', '') + '00';

    const icsContent = [
      'BEGIN:VCALENDAR',
      'VERSION:2.0',
      'BEGIN:VEVENT',
      `DTSTART:${dateFormatted}T${startTime}`,
      `DTEND:${dateFormatted}T${endTime}`,
      `SUMMARY:Visita Guiada - Biblioteca de Sobral (${formData.institutionName})`,
      `DESCRIPTION:Visita guiada para a turma ${formData.turma}. Responsável: ${formData.responsibleName}. Objetivo: ${formData.objective}`,
      'LOCATION:R. Randal Pompeu, S/N - Centro, Sobral - CE',
      'END:VEVENT',
      'END:VCALENDAR'
    ].join('\r\n');

    const blob = new Blob([icsContent], { type: 'text/calendar;charset=utf-8' });
    const link = document.createElement('a');
    link.href = window.URL.createObjectURL(blob);
    link.setAttribute('download', `visita-biblioteca-${dateFormatted}.ics`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleEmailConfirmation = () => {
    const subject = encodeURIComponent(`Confirmação de Agendamento - Biblioteca Municipal de Sobral`);
    const body = encodeURIComponent(
      `Olá, ${formData.responsibleName}!\n\n` +
      `Sua visita guiada à Biblioteca Municipal de Sobral Lustosa da Costa foi confirmada.\n\n` +
      `DETALHES DA VISITA:\n` +
      `- Data: ${format(date, "dd/MM/yyyy")}\n` +
      `- Horário: ${selectedSlot?.start} às ${selectedSlot?.end}\n` +
      `- Instituição: ${formData.institutionName}\n` +
      `- Público: ${formData.turma}\n` +
      `- Quantidade: ${formData.quantity} pessoas\n\n` +
      `Objetivo: ${formData.objective}\n\n` +
      `Local: R. Randal Pompeu, S/N - Centro, Sobral - CE.\n\n` +
      `Caso precise cancelar ou reagendar, entre em contato pelo e-mail: biblioteca@edu.sobral.ce.gov.br\n\n` +
      `Atenciosamente,\n` +
      `Equipe da Biblioteca Municipal de Sobral.`
    );
    window.location.href = `mailto:${formData.email}?subject=${subject}&body=${body}`;
  };

  const handlePrint = () => {
    window.print();
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedSlot) return;

    setIsSubmitting(true);

    try {
      const payload = {
        date: format(date, 'yyyy-MM-dd'),
        slot_start: selectedSlot.start,
        slot_end: selectedSlot.end,
        responsible_name: formData.responsibleName,
        institution_name: formData.institutionName,
        email: formData.email,
        turma: formData.turma,
        quantity: Number(formData.quantity),
        objective: formData.objective
      };

      const { error } = await supabase
        .from('bookings')
        .insert([payload]);

      if (error) throw error;

      onComplete({
        date,
        slot: selectedSlot,
        ...formData,
        quantity: Number(formData.quantity)
      });
      setStep('success');
    } catch (e: any) {
      console.error("Erro ao salvar no Supabase:", e);
      const errorMsg = e.message || (typeof e === 'object' ? JSON.stringify(e) : String(e));
      alert(`Ocorreu um erro ao salvar seu agendamento: ${errorMsg}`);
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
      <div className={`bg-white w-full max-w-2xl rounded-2xl shadow-2xl overflow-hidden max-h-[95vh] flex flex-col transition-all duration-300 print:shadow-none print:max-h-none print:w-full print:max-w-none`}>

        {step !== 'success' && (
          <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-white sticky top-0 z-10 print:hidden">
            <div>
              <h3 className="text-xl font-bold text-slate-800">
                Agendamento para {format(date, "dd 'de' MMMM", { locale: ptBR })}
              </h3>
              {selectedSlot && (
                <p className="text-[#800000] font-medium text-sm flex items-center mt-1">
                  <Clock size={14} className="mr-1" /> {selectedSlot.start} às {selectedSlot.end}
                </p>
              )}
            </div>
            <button onClick={onClose} className="p-2 hover:bg-slate-100 rounded-full transition-colors text-slate-400">
              <X size={24} />
            </button>
          </div>
        )}

        <div className="overflow-y-auto">
          {step === 'slot' && (
            <div className="p-6 space-y-4">
              <h4 className="text-lg font-semibold text-slate-700 mb-4">Escolha um dos 6 horários diários:</h4>
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                {TIME_SLOTS.map((slot, idx) => {
                  const occupied = isSlotTaken(slot);
                  return (
                    <button
                      key={idx}
                      disabled={occupied}
                      onClick={() => handleSlotSelect(slot)}
                      className={`
                        flex items-center justify-between p-4 border rounded-xl transition-all text-left group
                        ${occupied 
                          ? 'bg-slate-50 border-slate-100 opacity-60 cursor-not-allowed' 
                          : 'border-slate-200 hover:border-[#800000] hover:bg-red-50'
                        }
                      `}
                    >
                      <div className="flex items-center">
                        <div className={`
                          w-10 h-10 rounded-full flex items-center justify-center mr-3 transition-colors
                          ${occupied ? 'bg-slate-200 text-slate-400' : 'bg-red-50 text-[#800000] group-hover:bg-[#800000] group-hover:text-white'}
                        `}>
                          <Clock size={18} />
                        </div>
                        <span className={`font-semibold ${occupied ? 'text-slate-400' : 'text-slate-700'}`}>{slot.start} - {slot.end}</span>
                      </div>
                      <span className={`text-[10px] font-bold uppercase tracking-tighter ${occupied ? 'text-red-400' : 'text-green-500'}`}>
                        {occupied ? 'Ocupado' : 'Livre'}
                      </span>
                    </button>
                  );
                })}
              </div>
            </div>
          )}

          {step === 'form' && (
            <form onSubmit={handleSubmit} className="p-6 space-y-6">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-sm font-semibold text-slate-700 flex items-center">
                    <User size={16} className="mr-1 text-[#800000]" /> Nome do Responsável
                  </label>
                  <input
                    required
                    disabled={isSubmitting}
                    type="text"
                    value={formData.responsibleName}
                    onChange={e => setFormData(prev => ({ ...prev, responsibleName: e.target.value }))}
                    className="w-full px-4 py-2 bg-white border border-slate-200 rounded-lg focus:ring-2 focus:ring-[#800000] focus:border-transparent outline-none transition-all disabled:bg-slate-50"
                    placeholder="Nome completo"
                  />
                </div>

                <div className="space-y-2">
                  <label className="text-sm font-semibold text-slate-700 flex items-center">
                    <Building2 size={16} className="mr-1 text-[#800000]" /> Nome da Instituição
                  </label>
                  <input
                    required
                    disabled={isSubmitting}
                    type="text"
                    value={formData.institutionName}
                    onChange={e => setFormData(prev => ({ ...prev, institutionName: e.target.value }))}
                    className="w-full px-4 py-2 bg-white border border-slate-200 rounded-lg focus:ring-2 focus:ring-[#800000] focus:border-transparent outline-none transition-all disabled:bg-slate-50"
                    placeholder="Escola, Faculdade, ONG..."
                  />
                </div>

                <div className="space-y-2">
                  <label className="text-sm font-semibold text-slate-700 flex items-center">
                    <Mail size={16} className="mr-1 text-[#800000]" /> E-mail para confirmação
                  </label>
                  <input
                    required
                    disabled={isSubmitting}
                    type="email"
                    value={formData.email}
                    onChange={e => setFormData(prev => ({ ...prev, email: e.target.value }))}
                    className="w-full px-4 py-2 bg-white border border-slate-200 rounded-lg focus:ring-2 focus:ring-[#800000] focus:border-transparent outline-none transition-all disabled:bg-slate-50"
                    placeholder="email@exemplo.com"
                  />
                </div>

                <div className="space-y-2">
                  <label className="text-sm font-semibold text-slate-700 flex items-center">
                    <GraduationCap size={16} className="mr-1 text-[#800000]" /> Selecione a Turma
                  </label>
                  <select
                    disabled={isSubmitting}
                    value={formData.turma}
                    onChange={e => setFormData(prev => ({ ...prev, turma: e.target.value as Turma }))}
                    className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-[#800000] outline-none transition-all bg-white disabled:bg-slate-50"
                  >
                    {TURMAS.map(t => <option key={t} value={t}>{t}</option>)}
                  </select>
                </div>

                <div className="space-y-2">
                  <label className="text-sm font-semibold text-slate-700 flex items-center">
                    <Users size={16} className="mr-1 text-[#800000]" /> Qtd. Pessoas (Máx: 40)
                  </label>
                  <input
                    required
                    disabled={isSubmitting}
                    type="number"
                    min="1"
                    max="40"
                    value={formData.quantity}
                    onChange={e => setFormData(prev => ({ ...prev, quantity: e.target.value as any }))}
                    className="w-full px-4 py-2 bg-white border border-slate-200 rounded-lg focus:ring-2 focus:ring-[#800000] outline-none transition-all disabled:bg-slate-50"
                    placeholder="0"
                  />
                </div>
              </div>

              <div className="space-y-2">
                <div className="flex justify-between items-center">
                  <label className="text-sm font-semibold text-slate-700 flex items-center">
                    <FileText size={16} className="mr-1 text-[#800000]" /> Objetivo da Visita
                  </label>
                  <button
                    type="button"
                    onClick={handleSuggestObjective}
                    disabled={isGenerating || isSubmitting}
                    className="text-xs font-bold text-[#800000] flex items-center hover:bg-red-100 bg-red-50 px-2 py-1 rounded-md transition-colors disabled:opacity-50"
                  >
                    <Sparkles size={12} className="mr-1" /> {isGenerating ? 'Gerando...' : 'Sugerir com IA'}
                  </button>
                </div>
                <textarea
                  required
                  disabled={isSubmitting}
                  rows={3}
                  value={formData.objective}
                  onChange={e => setFormData(prev => ({ ...prev, objective: e.target.value }))}
                  className="w-full px-4 py-2 bg-white border border-slate-200 rounded-lg focus:ring-2 focus:ring-[#800000] outline-none transition-all resize-none disabled:bg-slate-50"
                  placeholder="Descreva de forma suscinta o objetivo pedagógico ou cultural da visita."
                />
              </div>

              <div className="flex space-x-3 pt-4 border-t border-slate-100">
                <button
                  type="button"
                  disabled={isSubmitting}
                  onClick={() => setStep('slot')}
                  className="flex-1 px-6 py-3 border border-slate-200 text-slate-600 font-bold rounded-xl hover:bg-slate-50 transition-colors disabled:opacity-50"
                >
                  Voltar
                </button>
                <button
                  type="submit"
                  disabled={isSubmitting}
                  className="flex-[2] px-6 py-3 bg-[#800000] text-white font-bold rounded-xl hover:bg-[#5a0000] shadow-lg shadow-red-900/20 transition-all active:scale-95 flex items-center justify-center disabled:bg-slate-400 disabled:shadow-none"
                >
                  {isSubmitting ? (
                    <>
                      <Loader2 className="animate-spin mr-2" size={20} />
                      Salvando agendamento...
                    </>
                  ) : 'Confirmar Agendamento'}
                </button>
              </div>
            </form>
          )}

          {step === 'success' && (
            <div className="flex flex-col bg-white min-h-full animate-in fade-in zoom-in duration-300">
              {/* Maroon Header */}
              <div className="bg-[#800000] p-8 text-center relative print:bg-white print:text-black print:border-b print:p-4">
                <button onClick={onClose} className="absolute top-4 right-4 p-2 hover:bg-white/10 rounded-full text-white/60 transition-colors print:hidden">
                  <X size={24} />
                </button>
                <div className="flex items-center justify-center space-x-3 mb-6 print:mb-2">
                  <div className="bg-white p-1.5 rounded-lg print:border print:border-black">
                    <BookOpen size={28} className="text-[#800000] print:text-black" />
                  </div>
                  <div className="flex flex-col text-left">
                    <h2 className="text-xl font-bold text-white tracking-tight leading-none uppercase print:text-black">Biblioteca Municipal de Sobral</h2>
                    <span className="text-[10px] font-medium text-white/70 uppercase tracking-widest print:text-black">Lustosa da Costa</span>
                  </div>
                </div>
                <h3 className="text-white text-sm font-bold tracking-[0.2em] uppercase print:text-black print:text-lg">Comprovante de Agendamento</h3>
              </div>

              <div className="p-8 space-y-8">
                <div className="space-y-2 print:hidden">
                  <h3 className="text-2xl font-extrabold text-slate-800">Tudo pronto, {formData.responsibleName.split(' ')[0]}!</h3>
                  <p className="text-slate-500 text-sm leading-relaxed">
                    Seu agendamento foi registrado. Para garantir que você não perca as informações, use os botões abaixo para salvar a confirmação.
                  </p>
                </div>

                {/* Grid de Botões de Ação */}
                <div className="grid grid-cols-1 sm:grid-cols-3 gap-3 print:hidden">
                  <button 
                    onClick={handleEmailConfirmation}
                    className="flex flex-col items-center justify-center p-4 bg-slate-50 border border-slate-200 rounded-xl hover:bg-[#800000] hover:text-white hover:border-[#800000] transition-all group"
                  >
                    <Send className="mb-2 text-[#800000] group-hover:text-white" size={20} />
                    <span className="text-[10px] font-bold uppercase tracking-wider">Enviar p/ E-mail</span>
                  </button>
                  <button 
                    onClick={generateICS}
                    className="flex flex-col items-center justify-center p-4 bg-slate-50 border border-slate-200 rounded-xl hover:bg-[#800000] hover:text-white hover:border-[#800000] transition-all group"
                  >
                    <Download className="mb-2 text-[#800000] group-hover:text-white" size={20} />
                    <span className="text-[10px] font-bold uppercase tracking-wider">Salvar no Calendário</span>
                  </button>
                  <button 
                    onClick={handlePrint}
                    className="flex flex-col items-center justify-center p-4 bg-slate-50 border border-slate-200 rounded-xl hover:bg-[#800000] hover:text-white hover:border-[#800000] transition-all group"
                  >
                    <Printer className="mb-2 text-[#800000] group-hover:text-white" size={20} />
                    <span className="text-[10px] font-bold uppercase tracking-wider">Imprimir Comprovante</span>
                  </button>
                </div>

                {/* Details Card */}
                <div className="border border-slate-200 rounded-2xl p-6 space-y-4 relative overflow-hidden bg-slate-50/50 print:bg-white print:border-none print:p-0">
                   <div className="absolute left-0 top-0 bottom-0 w-1 bg-[#800000] print:hidden"></div>

                   <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                     <div className="flex items-center text-slate-700">
                       <span className="w-8 h-8 rounded-lg bg-white shadow-sm flex items-center justify-center mr-3 print:hidden">
                         <CalendarIcon size={16} className="text-[#800000]" />
                       </span>
                       <p className="text-sm"><strong className="text-slate-900">Data:</strong> {format(date, "eeee, dd/MM/yyyy", { locale: ptBR })}</p>
                     </div>

                     <div className="flex items-center text-slate-700">
                       <span className="w-8 h-8 rounded-lg bg-white shadow-sm flex items-center justify-center mr-3 print:hidden">
                         <Clock size={16} className="text-[#800000]" />
                       </span>
                       <p className="text-sm"><strong className="text-slate-900">Horário:</strong> {selectedSlot?.start} às {selectedSlot?.end}</p>
