import React, { useState, useEffect } from 'react';
import { format } from 'date-fns';
import { ptBR } from 'date-fns/locale';
import { X, Clock, Users, GraduationCap, Building2, User, Mail, FileText, Sparkles, BookOpen, Calendar as CalendarIcon, CheckCircle2, Loader2, Send, ShieldCheck, AlertCircle, RefreshCw } from 'lucide-react';
import { TIME_SLOTS, TURMAS } from '../constants';
import { TimeSlot, Turma, BookingData } from '../types';
import { generateObjectiveSuggestion } from '../services/geminiService';
import { supabase } from '../services/supabase';

interface BookingDialogProps {
  date: Date;
  existingBookings: BookingData[];
  onClose: () => void;
  onComplete: (data: BookingData) => void;
}

const BookingDialog: React.FC<BookingDialogProps> = ({ date, existingBookings, onClose, onComplete }) => {
  const [step, setStep] = useState<'slot' | 'form' | 'success'>('slot');
  const [selectedSlot, setSelectedSlot] = useState<TimeSlot | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [emailStatus, setEmailStatus] = useState<'idle' | 'sending' | 'sent' | 'error'>('idle');
  const [formData, setFormData] = useState({
    responsibleName: '',
    institutionName: '',
    email: '',
    turma: Turma.INFANTIL,
    quantity: '' as unknown as number,
    objective: ''
  });
  const [isGenerating, setIsGenerating] = useState(false);

  const isSlotTaken = (slot: TimeSlot) => {
    const targetDateString = format(date, 'yyyy-MM-dd');
    return existingBookings.some(b => {
      const bookingDateStr = (b as any).dateString || (b.date instanceof Date ? format(b.date, 'yyyy-MM-dd') : b.date);
      return bookingDateStr === targetDateString && 
             b.slot.start === slot.start && 
             b.slot.end === slot.end;
    });
  };

  const handleSlotSelect = (slot: TimeSlot) => {
    if (isSlotTaken(slot)) return;
    setSelectedSlot(slot);
    setStep('form');
  };

  const handleSuggestObjective = async () => {
    if (!formData.institutionName) {
      alert("Por favor, informe o nome da instituição primeiro.");
      return;
    }
    setIsGenerating(true);
    const suggestion = await generateObjectiveSuggestion(formData.turma, formData.institutionName);
    setFormData(prev => ({ ...prev, objective: suggestion }));
    setIsGenerating(false);
  };

  const handleManualEmail = () => {
    const subject = encodeURIComponent(`CONFIRMAÇÃO: Visita Guiada - Biblioteca de Sobral`);
    const body = encodeURIComponent(
      `Olá, ${formData.responsibleName}!\n\n` +
      `Sua visita à Biblioteca Municipal de Sobral Lustosa da Costa foi agendada.\n\n` +
      `Data: ${format(date, "eeee, dd/MM/yyyy", { locale: ptBR })}\n` +
      `Horário: ${selectedSlot?.start} às ${selectedSlot?.end}\n` +
      `Instituição: ${formData.institutionName}\n\n` +
      `Atenciosamente,\nEquipe da Biblioteca Municipal de Sobral.`
    );
    window.location.href = `mailto:${formData.email}?subject=${subject}&body=${body}`;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedSlot) return;

    setIsSubmitting(true);
    setEmailStatus('sending');

    try {
      const payload = {
        date: format(date, 'yyyy-MM-dd'),
        slot_start: selectedSlot.start,
        slot_end: selectedSlot.end,
        responsible_name: formData.responsibleName,
        institution_name: formData.institutionName,
        email: formData.email,
        turma: formData.turma,
        quantity: Number(formData.quantity),
        objective: formData.objective
      };

      // 1. Salva no Banco de Dados
      const { error: dbError } = await supabase.from('bookings').insert([payload]);
      if (dbError) throw dbError;

      // 2. Chama a Edge Function para enviar e-mail automático
      // Nota: Se você ainda não criou a função no Supabase, ela retornará erro, mas o agendamento estará salvo.
      try {
        const { error: funcError } = await supabase.functions.invoke('send-confirmation-email', {
          body: payload
        });
        if (funcError) throw funcError;
        setEmailStatus('sent');
      } catch (fErr) {
        console.warn("Edge Function não encontrada ou erro no envio automático. Use o envio manual.");
        setEmailStatus('error');
      }

      onComplete({
        date,
        slot: selectedSlot,
        ...formData,
        quantity: Number(formData.quantity)
      });
      setStep('success');
    } catch (e: any) {
      console.error("Erro geral:", e);
      alert(`Erro: ${e.message || "Falha ao processar agendamento."}`);
      setEmailStatus('error');
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/70 backdrop-blur-md">
