                </div>
                <div className="space-y-2">
                  <label className="text-sm font-semibold text-slate-700">Instituição</label>
                  <input required disabled={isSubmitting} type="text" value={formData.institutionName} onChange={e => setFormData(prev => ({ ...prev, institutionName: e.target.value }))} className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-[#800000] outline-none" />
                </div>
                <div className="space-y-2">
                  <label className="text-sm font-semibold text-slate-700">E-mail</label>
                  <input required disabled={isSubmitting} type="email" value={formData.email} onChange={e => setFormData(prev => ({ ...prev, email: e.target.value }))} className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-[#800000] outline-none" />
                </div>
                <div className="space-y-2">
                  <label className="text-sm font-semibold text-slate-700">Pessoas (Máx: 40)</label>
                  <input required disabled={isSubmitting} type="number" max="40" value={formData.quantity} onChange={e => setFormData(prev => ({ ...prev, quantity: e.target.value as any }))} className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-[#800000] outline-none" />
                </div>
              </div>
              <div className="space-y-2">
                <div className="flex justify-between items-center">
                  <label className="text-sm font-semibold text-slate-700">Objetivo</label>
                  <button type="button" onClick={handleSuggestObjective} className="text-xs font-bold text-[#800000] bg-red-50 px-2 py-1 rounded-md"><Sparkles size={12} className="inline mr-1" /> IA Sugestão</button>
                </div>
                <textarea required disabled={isSubmitting} rows={3} value={formData.objective} onChange={e => setFormData(prev => ({ ...prev, objective: e.target.value }))} className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-[#800000] outline-none resize-none" />
              </div>
              <button type="submit" disabled={isSubmitting} className="w-full py-4 bg-[#800000] text-white font-bold rounded-xl flex items-center justify-center disabled:bg-slate-400">
                {isSubmitting ? <><Loader2 className="animate-spin mr-2" size={20} /> Processando...</> : 'Confirmar Agendamento'}
              </button>
            </form>
          )}

          {step === 'success' && (
            <div className="flex flex-col bg-white min-h-full animate-in fade-in zoom-in duration-500">
              <div className="bg-[#800000] p-10 text-center relative overflow-hidden">
                <div className="absolute top-0 left-0 w-full h-full opacity-10 pointer-events-none flex items-center justify-center"><ShieldCheck size={200} className="text-white rotate-12" /></div>
                <div className="relative z-10">
                  <div className="w-16 h-16 bg-white rounded-full flex items-center justify-center mx-auto mb-4 shadow-xl animate-bounce"><CheckCircle2 size={36} className="text-[#800000]" /></div>
                  <h2 className="text-3xl font-black text-white uppercase tracking-tight">Agendamento Realizado!</h2>
                </div>
              </div>

              <div className="p-8 space-y-6 flex flex-col items-center">

                {/* Status do E-mail Automático */}
                <div className={`w-full max-w-md p-6 rounded-3xl border-2 flex flex-col items-center text-center space-y-4 transition-all ${emailStatus === 'sent' ? 'bg-green-50 border-green-200' : 'bg-amber-50 border-amber-200'}`}>
                  <div className={`p-4 rounded-full text-white shadow-lg ${emailStatus === 'sent' ? 'bg-green-600' : 'bg-amber-600'}`}>
                    {emailStatus === 'sent' ? <ShieldCheck size={32} /> : <RefreshCw className="animate-spin" size={32} />}
                  </div>

                  <div>
                    <h4 className={`text-lg font-black uppercase tracking-tight ${emailStatus === 'sent' ? 'text-green-900' : 'text-amber-900'}`}>
                      {emailStatus === 'sent' ? 'E-mail enviado automaticamente!' : 'Verificando envio automático...'}
                    </h4>
                    <p className={`text-sm mt-2 ${emailStatus === 'sent' ? 'text-green-800' : 'text-amber-800'}`}>
                      {emailStatus === 'sent' 
                        ? `Um comprovante foi enviado para ${formData.email} através do nosso servidor.` 
                        : 'Nosso sistema está tentando despachar o e-mail em segundo plano.'}
                    </p>
                  </div>

                  {emailStatus === 'error' && (
                    <div className="bg-white p-4 rounded-2xl border border-amber-200 w-full">
                       <p className="text-xs text-amber-700 font-bold mb-3 flex items-center justify-center">
                         <AlertCircle size={14} className="mr-1" /> Envio automático pendente de configuração.
                       </p>
                       <button onClick={handleManualEmail} className="w-full bg-amber-600 text-white py-3 rounded-xl font-bold text-sm uppercase flex items-center justify-center hover:bg-amber-700 transition-colors">
                         <Send size={16} className="mr-2" /> Enviar Manualmente Agora
                       </button>
                    </div>
                  )}
                </div>

                <div className="w-full max-w-md border-t border-slate-100 pt-6 space-y-2">
                   <p className="text-sm text-center text-slate-500">
                     Sua visita está confirmada para <strong>{format(date, "dd/MM/yyyy")}</strong> às <strong>{selectedSlot?.start}</strong>.
                   </p>
                </div>

                <button onClick={onClose} className="bg-slate-900 text-white px-10 py-3.5 rounded-xl font-bold hover:bg-slate-800 active:scale-95 transition-all">
                  Finalizar e Sair
                </button>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default BookingDialog;

payload.text:
### Como configurar a Edge Function no Supabase para envio real:

Para que o e-mail seja enviado "sozinho", você deve criar uma função no Supabase. Siga estes passos rápidos:

1.  Crie uma conta no **[Resend.com](https://resend.com)** e gere uma **API KEY**.
2.  No terminal do seu computador (com o Supabase CLI instalado), execute:
    `supabase functions new send-confirmation-email`
3.  Cole este código no arquivo `index.ts` da função gerada:

```typescript
import { serve } from "https://deno.land/std@0.168.0/http/server.ts"

const RESEND_API_KEY = "SUA_API_KEY_DO_RESEND_AQUI";

serve(async (req) => {
  const { responsible_name, email, date, slot_start, institution_name } = await req.json();

  const res = await fetch("https://api.resend.com/emails", {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      Authorization: `Bearer ${RESEND_API_KEY}`,
    },
    body: JSON.stringify({
      from: "Biblioteca de Sobral <onboarding@resend.dev>", // Ou seu domínio verificado
      to: [email],
      subject: "Confirmação de Agendamento - Biblioteca Municipal",
      html: `<h1>Olá, ${responsible_name}!</h1>
             <p>Sua visita para a instituição <strong>${institution_name}</strong> está confirmada.</p>
             <p><strong>Data:</strong> ${date}<br><strong>Horário:</strong> ${slot_start}</p>
             <p>Local: R. Randal Pompeu, S/N - Centro, Sobral - CE.</p>`,
    }),
  });

  const data = await res.json();
  return new Response(JSON.stringify(data), { headers: { "Content-Type": "application/json" } });
})
```

4.  Dê o deploy: `supabase functions deploy send-confirmation-email`.

Desta forma, o front-end apenas "avisa" o servidor, e o servidor faz o trabalho pesado de enviar o e-mail sem precisar da interação do usuário! No código que eu te mandei agora, eu já adicionei o tratamento visual para isso. Se a função não estiver pronta, o sistema avisa e dá o botão de "Enviar Manualmente".

