export enum Turma {
  INFANTIL = 'Educação Infantil',
  FUNDAMENTAL_1 = 'Ensino Fundamental I',
  FUNDAMENTAL_2 = 'Ensino Fundamental II',
  ENSINO_MEDIO = 'Ensino Médio',
  EJA = 'EJA (Educação de Jovens e Adultos)',
  UNIVERSITARIO = 'Universitário',
  OUTROS = 'Outros'
}

export interface TimeSlot {
  start: string;
  end: string;
}

export interface BookingData {
  id?: string; // UUID do Supabase
  date: Date;
  slot: TimeSlot;
  responsibleName: string;
  institutionName: string;
  email: string;
  turma: Turma;
  quantity: number;
  objective: string;
  status?: 'pending' | 'confirmed';
}

export interface Holiday {
  date: string; // ISO format YYYY-MM-DD
  name: string;
}

import React, { useState } from 'react';
import { format } from 'date-fns';
import { ptBR } from 'date-fns/locale';
import { X, Clock, Users, GraduationCap, Building2, User, Mail, FileText, Sparkles, CheckCircle2, Loader2, ShieldCheck, AlertCircle } from 'lucide-react';
import { TIME_SLOTS, TURMAS } from '../constants';
import { TimeSlot, Turma, BookingData } from '../types';
import { generateObjectiveSuggestion } from '../services/geminiService';
import { supabase } from '../services/supabase';

interface BookingDialogProps {
  date: Date;
  existingBookings: BookingData[];
  onClose: () => void;
  onComplete: (data: BookingData) => void;
}

const BookingDialog: React.FC<BookingDialogProps> = ({ date, existingBookings, onClose, onComplete }) => {
  const [step, setStep] = useState<'slot' | 'form' | 'success'>('slot');
  const [selectedSlot, setSelectedSlot] = useState<TimeSlot | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [formData, setFormData] = useState({
    responsibleName: '',
    institutionName: '',
    email: '',
    turma: Turma.INFANTIL,
    quantity: '' as unknown as number,
    objective: ''
  });
  const [isGenerating, setIsGenerating] = useState(false);

  const isSlotTaken = (slot: TimeSlot) => {
    const targetDateString = format(date, 'yyyy-MM-dd');
    return existingBookings.some(b => {
      const bookingDateStr = (b as any).dateString || (b.date instanceof Date ? format(b.date, 'yyyy-MM-dd') : b.date);
      return bookingDateStr === targetDateString && 
             b.slot.start === slot.start && 
             b.slot.end === slot.end &&
             b.status !== 'pending'; // Slots pendentes talvez pudessem ser mostrados, mas vamos considerar apenas confirmados como "bloqueados"
    });
  };

  const handleSlotSelect = (slot: TimeSlot) => {
    if (isSlotTaken(slot)) return;
    setSelectedSlot(slot);
    setStep('form');
  };

  const handleSuggestObjective = async () => {
    if (!formData.institutionName) {
      alert("Por favor, informe o nome da instituição primeiro.");
      return;
    }
    setIsGenerating(true);
    const suggestion = await generateObjectiveSuggestion(formData.turma, formData.institutionName);
    setFormData(prev => ({ ...prev, objective: suggestion }));
    setIsGenerating(false);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedSlot) return;

    setIsSubmitting(true);

    try {
      const payload = {
        date: format(date, 'yyyy-MM-dd'),
        slot_start: selectedSlot.start,
        slot_end: selectedSlot.end,
        responsible_name: formData.responsibleName,
        institution_name: formData.institutionName,
        email: formData.email,
        turma: formData.turma,
        quantity: Number(formData.quantity),
        objective: formData.objective,
        status: 'pending' // Importante: Salva como pendente
      };

      const { error: dbError } = await supabase.from('bookings').insert([payload]);
      if (dbError) throw dbError;

      onComplete({
        date,
        slot: selectedSlot,
        ...formData,
        quantity: Number(formData.quantity),
        status: 'pending'
      });
      setStep('success');
    } catch (e: any) {
      console.error("Erro geral:", e);
      alert(`Erro: ${e.message || "Falha ao processar solicitação."}`);
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/70 backdrop-blur-md">
      <div className={`bg-white w-full max-w-2xl rounded-2xl shadow-2xl overflow-hidden max-h-[95vh] flex flex-col transition-all duration-300`}>

        {step !== 'success' && (
          <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-white sticky top-0 z-10">
            <div>
              <h3 className="text-xl font-bold text-slate-800">
                Solicitar Visita para {format(date, "dd 'de' MMMM", { locale: ptBR })}
              </h3>
            </div>
            <button onClick={onClose} className="p-2 hover:bg-slate-100 rounded-full transition-colors text-slate-400">
              <X size={24} />
            </button>
          </div>
        )}

        <div className="overflow-y-auto">
          {step === 'slot' && (
            <div className="p-6 space-y-4">
              <h4 className="text-lg font-semibold text-slate-700 mb-4 text-center">Horários Disponíveis</h4>
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                {TIME_SLOTS.map((slot, idx) => {
                  const occupied = isSlotTaken(slot);
                  return (
                    <button
                      key={idx}
                      disabled={occupied}
                      onClick={() => handleSlotSelect(slot)}
                      className={`flex items-center justify-between p-4 border rounded-xl transition-all ${occupied ? 'bg-red-50 border-red-100 opacity-90' : 'border-slate-200 hover:border-[#800000] hover:bg-red-50'}`}
                    >
                      <span className="font-semibold">{slot.start} - {slot.end}</span>
                      <span className={`text-[10px] font-bold uppercase ${occupied ? 'text-red-600' : 'text-green-500'}`}>{occupied ? 'Ocupado' : 'Disponível'}</span>
                    </button>
                  );
                })}
              </div>
            </div>
          )}

          {step === 'form' && (
            <form onSubmit={handleSubmit} className="p-6 space-y-6">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-1">
                  <label className="text-xs font-bold text-slate-500 uppercase tracking-wider flex items-center"><User size={12} className="mr-1" /> Responsável</label>
                  <input required disabled={isSubmitting} type="text" value={formData.responsibleName} onChange={e => setFormData(prev => ({ ...prev, responsibleName: e.target.value }))} className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-[#800000] outline-none" />
                </div>
                <div className="space-y-1">
                  <label className="text-xs font-bold text-slate-500 uppercase tracking-wider flex items-center"><Building2 size={12} className="mr-1" /> Instituição</label>
                  <input required disabled={isSubmitting} type="text" value={formData.institutionName} onChange={e => setFormData(prev => ({ ...prev, institutionName: e.target.value }))} className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-[#800000] outline-none" />
                </div>
                <div className="space-y-1">
                  <label className="text-xs font-bold text-slate-500 uppercase tracking-wider flex items-center"><Mail size={12} className="mr-1" /> E-mail</label>
                  <input required disabled={isSubmitting} type="email" value={formData.email} onChange={e => setFormData(prev => ({ ...prev, email: e.target.value }))} className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-[#800000] outline-none" />
                </div>
                <div className="space-y-1">
                  <label className="text-xs font-bold text-slate-500 uppercase tracking-wider flex items-center"><Users size={12} className="mr-1" /> Pessoas (Máx: 40)</label>
                  <input required disabled={isSubmitting} type="number" max="40" value={formData.quantity} onChange={e => setFormData(prev => ({ ...prev, quantity: e.target.value as any }))} className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-[#800000] outline-none" />
                </div>
              </div>
              <div className="space-y-1">
                <div className="flex justify-between items-center mb-1">
                   <label className="text-xs font-bold text-slate-500 uppercase tracking-wider flex items-center"><FileText size={12} className="mr-1" /> Objetivo Pedagógico</label>
                   <button type="button" onClick={handleSuggestObjective} className="text-[10px] font-bold text-[#800000] bg-red-50 px-2 py-1 rounded-md border border-red-100"><Sparkles size={10} className="inline mr-1" /> Sugerir com IA</button>
                </div>
                <textarea required disabled={isSubmitting} rows={3} value={formData.objective} onChange={e => setFormData(prev => ({ ...prev, objective: e.target.value }))} className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-[#800000] outline-none resize-none" />
              </div>
              <button type="submit" disabled={isSubmitting} className="w-full py-4 bg-[#800000] text-white font-bold rounded-xl flex items-center justify-center disabled:bg-slate-400 shadow-lg shadow-red-900/20 active:scale-95 transition-all">
                {isSubmitting ? <><Loader2 className="animate-spin mr-2" size={20} /> Enviando solicitação...</> : 'Enviar Solicitação de Visita'}
              </button>
            </form>
          )}

          {step === 'success' && (
            <div className="flex flex-col bg-white min-h-full animate-in fade-in zoom-in duration-500">
              <div className="bg-[#800000] p-10 text-center">
                <div className="w-16 h-16 bg-white rounded-full flex items-center justify-center mx-auto mb-4 shadow-xl"><ShieldCheck size={36} className="text-[#800000]" /></div>
                <h2 className="text-2xl font-black text-white uppercase tracking-tight">Solicitação Enviada!</h2>
              </div>

              <div className="p-8 space-y-6 flex flex-col items-center text-center">
                <div className="bg-amber-50 border-2 border-amber-200 p-6 rounded-3xl w-full max-w-md">
                   <AlertCircle size={32} className="text-amber-600 mx-auto mb-3" />
                   <h4 className="text-amber-900 font-bold uppercase text-sm mb-2 tracking-widest">Aguarde a Confirmação</h4>
                   <p className="text-amber-800 text-sm leading-relaxed">
                     Sua solicitação foi registrada no sistema. Nossa equipe analisará os dados e, em breve, você receberá um <strong>e-mail de confirmação</strong> com todos os detalhes da visita.
                   </p>
                </div>

                <div className="space-y-1">
                  <p className="text-xs text-slate-400 font-bold uppercase tracking-widest">Protocolo de Solicitação:</p>
                  <p className="text-sm font-bold text-slate-700">#{Math.random().toString(36).substr(2, 9).toUpperCase()}</p>
                </div>

                <button onClick={onClose} className="bg-slate-900 text-white px-12 py-4 rounded-2xl font-black uppercase tracking-widest text-xs hover:bg-slate-800 active:scale-95 transition-all shadow-xl">
                  Entendido e Sair
                </button>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default BookingDialog;

import React, { useState, useEffect } from 'react';
import { supabase } from '../services/supabase';
import { BookingData } from '../types';
import { format } from 'date-fns';
import { ptBR } from 'date-fns/locale';
import { 
  CheckCircle2, 
  Clock, 
  Search, 
  Filter, 
  User, 
  Mail, 
  Building2, 
  Users, 
  ChevronRight, 
  Loader2, 
  LogOut, 
  AlertTriangle,
  Send
} from 'lucide-react';

const AdminDashboard: React.FC<{ onLogout: () => void }> = ({ onLogout }) => {
  const [requests, setRequests] = useState<BookingData[]>([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState<'all' | 'pending' | 'confirmed'>('pending');
  const [confirmingId, setConfirmingId] = useState<string | null>(null);

  const fetchRequests = async () => {
    setLoading(true);
    const { data, error } = await supabase
      .from('bookings')
      .select('*')
      .order('date', { ascending: true });

    if (data) {
      const formatted = data.map((b: any) => ({
        ...b,
        date: new Date(b.date + 'T12:00:00'),
        slot: { start: b.slot_start, end: b.slot_end },
        responsibleName: b.responsible_name,
        institutionName: b.institution_name,
      }));
      setRequests(formatted);
    }
    setLoading(false);
  };

  useEffect(() => {
    fetchRequests();
  }, []);

  const handleConfirm = async (req: BookingData) => {
    if (!req.id) return;
    setConfirmingId(req.id);

    try {
      // 1. Atualiza Status no Banco
      const { error: updateError } = await supabase
        .from('bookings')
        .update({ status: 'confirmed' })
        .eq('id', req.id);

      if (updateError) throw updateError;

      // 2. Chama Edge Function para enviar e-mail
      const payload = {
        responsible_name: req.responsibleName,
        email: req.email,
        date: format(req.date, 'dd/MM/yyyy'),
        slot_start: req.slot.start,
        institution_name: req.institutionName,
        objective: req.objective
      };

      await supabase.functions.invoke('send-confirmation-email', {
        body: payload
      });

      // Recarrega lista
      await fetchRequests();
      alert("Agendamento confirmado e e-mail enviado com sucesso!");
    } catch (e: any) {
      console.error(e);
      alert("Erro ao confirmar agendamento: " + e.message);
    } finally {
      setConfirmingId(null);
    }
  };

  const filteredRequests = requests.filter(r => {
    if (filter === 'all') return true;
    return r.status === filter;
  });

  return (
    <div className="min-h-screen bg-slate-50">
      <header className="bg-white border-b border-slate-200 sticky top-0 z-30 px-6 h-16 flex items-center justify-between">
        <div className="flex items-center space-x-2">
          <div className="bg-[#800000] p-1.5 rounded-lg text-white">
            <ShieldCheck size={20} />
          </div>
          <h1 className="font-black text-slate-800 uppercase tracking-tighter text-sm">Gerenciamento de Visitas</h1>
        </div>
        <button onClick={onLogout} className="text-slate-400 hover:text-red-600 transition-colors flex items-center text-xs font-bold uppercase tracking-widest">
          <LogOut size={16} className="mr-1" /> Sair
        </button>
      </header>

      <main className="max-w-6xl mx-auto p-6 space-y-6">
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
          <div className="flex bg-white p-1 rounded-xl border border-slate-200 shadow-sm w-fit">
            {(['pending', 'confirmed', 'all'] as const).map(f => (
              <button
                key={f}
                onClick={() => setFilter(f)}
                className={`px-4 py-2 rounded-lg text-xs font-bold uppercase tracking-wider transition-all ${filter === f ? 'bg-[#800000] text-white' : 'text-slate-400 hover:text-slate-600'}`}
              >
                {f === 'pending' ? 'Pendentes' : f === 'confirmed' ? 'Confirmados' : 'Todos'}
              </button>
            ))}
          </div>

          <div className="text-sm text-slate-500 font-medium">
             Mostrando <strong>{filteredRequests.length}</strong> solicitações
          </div>
        </div>

        {loading ? (
          <div className="flex flex-col items-center justify-center py-20 text-slate-400">
            <Loader2 className="animate-spin mb-4" size={40} />
            <p className="font-bold uppercase tracking-widest text-xs">Carregando solicitações...</p>
          </div>
        ) : filteredRequests.length === 0 ? (
          <div className="bg-white border-2 border-dashed border-slate-200 rounded-3xl py-20 flex flex-col items-center justify-center text-slate-400">
             <Search size={48} className="mb-4 opacity-20" />
             <p className="font-bold">Nenhuma solicitação encontrada.</p>
          </div>
        ) : (
          <div className="grid grid-cols-1 gap-4">
            {filteredRequests.map((req) => (
              <div key={req.id} className="bg-white border border-slate-200 rounded-2xl p-5 hover:shadow-lg transition-all flex flex-col md:flex-row md:items-center justify-between gap-6 group">
                <div className="space-y-3 flex-grow">
                  <div className="flex items-center space-x-3">
                    <span className={`px-2 py-0.5 rounded text-[10px] font-black uppercase tracking-widest ${req.status === 'confirmed' ? 'bg-green-100 text-green-700' : 'bg-amber-100 text-amber-700'}`}>
                      {req.status === 'confirmed' ? 'Confirmado' : 'Pendente'}
                    </span>
                    <span className="text-slate-300 text-xs font-medium">#{req.id?.slice(0,8)}</span>
                  </div>

                  <div className="flex flex-col md:flex-row md:items-center gap-4">
                    <div className="flex items-center text-slate-800 font-bold text-lg">
