import React, { useState, useEffect } from 'react';
import { supabase } from '../services/supabase';
import { BookingData } from '../types';
import { format } from 'date-fns';
import { ptBR } from 'date-fns/locale';
import { 
  CheckCircle2, 
  Clock, 
  Search, 
  Filter, 
  User, 
  Mail, 
  Building2, 
  Users, 
  ChevronRight, 
  Loader2, 
  LogOut, 
  AlertTriangle,
  Send,
  ShieldCheck
} from 'lucide-react';

const AdminDashboard: React.FC<{ onLogout: () => void }> = ({ onLogout }) => {
  const [requests, setRequests] = useState<BookingData[]>([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState<'all' | 'pending' | 'confirmed'>('pending');
  const [confirmingId, setConfirmingId] = useState<string | null>(null);

  const fetchRequests = async () => {
    setLoading(true);
    try {
      const { data, error } = await supabase
        .from('bookings')
        .select('*')
        .order('date', { ascending: true });

      if (data) {
        const formatted = data.map((b: any) => ({
          ...b,
          date: new Date(b.date + 'T12:00:00'),
          slot: { start: b.slot_start, end: b.slot_end },
          responsibleName: b.responsible_name,
          institutionName: b.institution_name,
        }));
        setRequests(formatted);
      }
    } catch (e) {
      console.error("Erro ao carregar solicitações:", e);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchRequests();
  }, []);

  const handleConfirm = async (req: BookingData) => {
    if (!req.id) return;

    const confirmAction = window.confirm(`Deseja confirmar a visita da instituição ${req.institutionName} e enviar o e-mail oficial?`);
    if (!confirmAction) return;

    setConfirmingId(req.id);

    try {
      // 1. Atualiza Status no Banco
      const { error: updateError } = await supabase
        .from('bookings')
        .update({ status: 'confirmed' })
        .eq('id', req.id);

      if (updateError) throw updateError;

      // 2. Chama Edge Function para enviar e-mail
      const payload = {
        responsible_name: req.responsibleName,
        email: req.email,
        date: format(req.date, 'dd/MM/yyyy'),
        slot_start: req.slot.start,
        institution_name: req.institutionName,
        objective: req.objective
      };

      try {
        await supabase.functions.invoke('send-confirmation-email', {
          body: payload
        });
      } catch (emailErr) {
        console.warn("Agendamento atualizado no banco, mas houve falha no envio do e-mail automático:", emailErr);
        alert("Agendamento confirmado no sistema, mas o e-mail falhou. Por favor, envie manualmente.");
      }

      // Recarrega lista
      await fetchRequests();
      alert("Sucesso! Agendamento confirmado.");
    } catch (e: any) {
      console.error(e);
      alert("Erro ao confirmar agendamento: " + e.message);
    } finally {
      setConfirmingId(null);
    }
  };

  const filteredRequests = requests.filter(r => {
    if (filter === 'all') return true;
    return r.status === filter;
  });

  return (
    <div className="min-h-screen bg-slate-50">
      <header className="bg-white border-b border-slate-200 sticky top-0 z-30 px-6 h-16 flex items-center justify-between shadow-sm">
        <div className="flex items-center space-x-2">
          <div className="bg-[#800000] p-1.5 rounded-lg text-white">
            <ShieldCheck size={20} />
          </div>
          <h1 className="font-black text-slate-800 uppercase tracking-tighter text-sm">Gerenciamento de Visitas</h1>
        </div>
        <button onClick={onLogout} className="text-slate-400 hover:text-red-600 transition-colors flex items-center text-xs font-bold uppercase tracking-widest">
          <LogOut size={16} className="mr-1" /> Sair
        </button>
      </header>

      <main className="max-w-6xl mx-auto p-6 space-y-6">
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
          <div className="flex bg-white p-1 rounded-xl border border-slate-200 shadow-sm w-fit">
            {(['pending', 'confirmed', 'all'] as const).map(f => (
              <button
                key={f}
                onClick={() => setFilter(f)}
                className={`px-4 py-2 rounded-lg text-xs font-bold uppercase tracking-wider transition-all ${filter === f ? 'bg-[#800000] text-white' : 'text-slate-400 hover:text-slate-600'}`}
              >
                {f === 'pending' ? 'Pendentes' : f === 'confirmed' ? 'Confirmados' : 'Todos'}
              </button>
            ))}
          </div>

          <div className="text-sm text-slate-500 font-medium">
             Mostrando <strong>{filteredRequests.length}</strong> solicitações
          </div>
        </div>

        {loading ? (
          <div className="flex flex-col items-center justify-center py-20 text-slate-400">
            <Loader2 className="animate-spin mb-4" size={40} />
            <p className="font-bold uppercase tracking-widest text-xs">Carregando solicitações...</p>
          </div>
        ) : filteredRequests.length === 0 ? (
          <div className="bg-white border-2 border-dashed border-slate-200 rounded-3xl py-20 flex flex-col items-center justify-center text-slate-400">
             <Search size={48} className="mb-4 opacity-20" />
             <p className="font-bold">Nenhuma solicitação encontrada.</p>
          </div>
        ) : (
          <div className="grid grid-cols-1 gap-4">
            {filteredRequests.map((req) => (
              <div key={req.id} className="bg-white border border-slate-200 rounded-2xl p-5 hover:shadow-lg transition-all flex flex-col md:flex-row md:items-center justify-between gap-6 group">
                <div className="space-y-3 flex-grow">
                  <div className="flex items-center space-x-3">
                    <span className={`px-2 py-0.5 rounded text-[10px] font-black uppercase tracking-widest ${req.status === 'confirmed' ? 'bg-green-100 text-green-700' : 'bg-amber-100 text-amber-700'}`}>
                      {req.status === 'confirmed' ? 'Confirmado' : 'Pendente'}
                    </span>
                    <span className="text-slate-300 text-xs font-medium">#{req.id?.slice(0,8)}</span>
                  </div>

                  <div className="flex flex-col md:flex-row md:items-center gap-4">
                    <div className="flex items-center text-slate-800 font-bold text-lg">
                      <Clock size={18} className="mr-2 text-[#800000]" />
                      {format(req.date, 'dd/MM/yyyy')} às {req.slot.start}
                    </div>
                    <div className="flex items-center text-slate-600 text-sm">
                      <Building2 size={16} className="mr-1.5" />
                      {req.institutionName}
                    </div>
                  </div>

                  <div className="grid grid-cols-1 sm:grid-cols-3 gap-4 text-xs font-medium text-slate-500">
                     <div className="flex items-center"><User size={14} className="mr-1" /> {req.responsibleName}</div>
                     <div className="flex items-center"><Mail size={14} className="mr-1" /> {req.email}</div>
                     <div className="flex items-center"><Users size={14} className="mr-1" /> {req.quantity} pessoas</div>
                  </div>
                </div>

                <div className="flex items-center gap-3">
                  {req.status === 'pending' ? (
                    <button
                      onClick={() => handleConfirm(req)}
                      disabled={confirmingId === req.id}
                      className="bg-green-600 hover:bg-green-700 text-white px-6 py-3 rounded-xl font-bold text-sm flex items-center transition-all disabled:bg-slate-300 active:scale-95 shadow-md shadow-green-900/10"
                    >
                      {confirmingId === req.id ? <Loader2 className="animate-spin mr-2" size={18} /> : <CheckCircle2 className="mr-2" size={18} />}
                      Confirmar
                    </button>
                  ) : (
                    <div className="flex items-center text-green-600 text-sm font-bold bg-green-50 px-4 py-2 rounded-lg">
                      <Send size={14} className="mr-2" /> E-mail Enviado
                    </div>
                  )}
                  <div className="h-10 w-10 flex items-center justify-center rounded-lg bg-slate-50 text-slate-300 group-hover:text-slate-400">
                     <ChevronRight size={20} />
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </main>
    </div>
  );
};

export default AdminDashboard;

import React, { useState } from 'react';
import { 
  format, 
  addMonths, 
  subMonths, 
  startOfMonth, 
  endOfMonth, 
  startOfWeek, 
  endOfWeek, 
  isSameMonth, 
  isSameDay, 
  addDays, 
  isWeekend, 
  isBefore, 
  startOfToday
} from 'date-fns';
import { ptBR } from 'date-fns/locale';
import { ChevronLeft, ChevronRight, Info, CheckCircle2 } from 'lucide-react';
import { BRAZILIAN_HOLIDAYS } from '../constants';
import { BookingData } from '../types';

interface CalendarProps {
  onSelectDate: (date: Date) => void;
  selectedDate: Date | null;
  bookings: BookingData[];
}

const Calendar: React.FC<CalendarProps> = ({ onSelectDate, selectedDate, bookings }) => {
  const [currentMonth, setCurrentMonth] = useState(new Date());
  const today = startOfToday();

  const nextMonth = () => setCurrentMonth(addMonths(currentMonth, 1));
  const prevMonth = () => setCurrentMonth(subMonths(currentMonth, 1));

  const isHoliday = (date: Date) => {
    const dateStr = format(date, 'yyyy-MM-dd');
    return BRAZILIAN_HOLIDAYS.some(h => h.date === dateStr);
  };

  const getHolidayName = (date: Date) => {
    const dateStr = format(date, 'yyyy-MM-dd');
    return BRAZILIAN_HOLIDAYS.find(h => h.date === dateStr)?.name;
  };

  const getConfirmedBookingsCount = (date: Date) => {
    const dateStr = format(date, 'yyyy-MM-dd');
    return bookings.filter(b => {
      const bDateStr = (b as any).dateString || (b.date instanceof Date ? format(b.date, 'yyyy-MM-dd') : b.date);
      return bDateStr === dateStr && b.status === 'confirmed';
    }).length;
  };

  const renderHeader = () => {
    return (
      <div className="flex items-center justify-between mb-6">
        <h2 className="text-2xl font-bold text-slate-800 capitalize">
          {format(currentMonth, 'MMMM yyyy', { locale: ptBR })}
        </h2>
        <div className="flex space-x-2">
          <button
            onClick={prevMonth}
            className="p-2 hover:bg-slate-200 rounded-full transition-colors"
            title="Mês Anterior"
          >
            <ChevronLeft size={24} />
          </button>
          <button
            onClick={nextMonth}
            className="p-2 hover:bg-slate-200 rounded-full transition-colors"
            title="Próximo Mês"
          >
            <ChevronRight size={24} />
          </button>
        </div>
      </div>
    );
  };

  const renderDays = () => {
    const days = ['Dom', 'Seg', 'Ter', 'Qua', 'Qui', 'Sex', 'Sáb'];
    return (
      <div className="grid grid-cols-7 mb-2">
        {days.map((day, index) => (
          <div key={index} className="text-center text-xs font-bold text-slate-400 uppercase tracking-wider">
            {day}
          </div>
        ))}
      </div>
    );
  };

  const renderCells = () => {
    const monthStart = startOfMonth(currentMonth);
    const monthEnd = endOfMonth(monthStart);
    const startDate = startOfWeek(monthStart);
    const endDate = endOfWeek(monthEnd);

    const rows = [];
    let days = [];
    let day = startDate;

    while (day <= endDate) {
      for (let i = 0; i < 7; i++) {
        const formattedDate = format(day, 'd');
        const cloneDay = day;
        const isDisabled = isWeekend(day) || isHoliday(day) || isBefore(day, today);
        const holidayName = getHolidayName(day);
        const confirmedCount = getConfirmedBookingsCount(day);

        days.push(
          <div
            key={day.toString()}
            className={`
              relative h-24 sm:h-32 border-t border-l border-slate-100 p-2 cursor-pointer transition-all
              ${!isSameMonth(day, monthStart) ? 'bg-slate-50 text-slate-300 pointer-events-none' : ''}
              ${isDisabled ? 'bg-slate-50 text-slate-400 cursor-not-allowed' : 'hover:bg-red-50/50'}
              ${selectedDate && isSameDay(day, selectedDate) ? 'bg-red-50 ring-2 ring-[#800000] z-10' : ''}
            `}
            onClick={() => !isDisabled && onSelectDate(cloneDay)}
          >
            <span className={`text-sm font-semibold inline-flex items-center justify-center w-8 h-8 rounded-full ${isSameDay(day, today) ? 'text-white bg-[#800000] shadow-md shadow-red-900/30' : ''}`}>
              {formattedDate}
            </span>

            {confirmedCount > 0 && !holidayName && (
               <div className="absolute bottom-2 right-2 flex items-center space-x-1 bg-green-100 px-1.5 py-0.5 rounded text-[10px] font-black text-green-700 uppercase">
                 <CheckCircle2 size={10} />
                 <span>{confirmedCount} Visita{confirmedCount > 1 ? 's' : ''}</span>
               </div>
            )}

            {holidayName && (
              <div className="mt-1 text-[10px] sm:text-xs text-red-700 font-bold leading-tight">
                {holidayName}
              </div>
            )}
            {isDisabled && isSameMonth(day, monthStart) && !holidayName && (
              <div className="mt-1 text-[10px] text-slate-400 uppercase font-medium">Indisponível</div>
            )}
          </div>
        );
        day = addDays(day, 1);
      }
      rows.push(
        <div className="grid grid-cols-7 border-r border-b border-slate-100" key={day.toString()}>
          {days}
        </div>
      );
      days = [];
    }
    return <div className="bg-white rounded-xl shadow-sm overflow-hidden border border-slate-200">{rows}</div>;
  };

  return (
    <div className="w-full max-w-5xl mx-auto p-4 sm:p-6 bg-white rounded-2xl shadow-lg border border-slate-200">
      <div className="mb-6 flex items-center text-sm text-[#800000] bg-red-50 p-4 rounded-xl border border-red-100/50">
        <Info className="mr-3 text-[#800000] flex-shrink-0" size={20} />
        <p className="font-medium">Selecione uma data disponível para realizar o agendamento da visita do seu grupo.</p>
      </div>
      {renderHeader()}
      {renderDays()}
      {renderCells()}
    </div>
  );
};

