             <Search size={48} className="mb-4 opacity-20" />
             <p className="font-bold">Nenhum registro encontrado nesta categoria.</p>
          </div>
        ) : (
          <div className="grid grid-cols-1 gap-4">
            {filteredRequests.map((req) => (
              <div key={req.id} className="bg-white border border-slate-200 rounded-2xl p-5 hover:border-slate-300 transition-all flex flex-col md:flex-row md:items-center justify-between gap-6 group">
                <div className="space-y-3 flex-grow">
                  <div className="flex items-center space-x-3">
                    <span className={`px-2 py-0.5 rounded text-[10px] font-black uppercase tracking-widest flex items-center ${req.status === 'confirmed' ? 'bg-green-100 text-green-700' : 'bg-blue-100 text-blue-700'}`}>
                      {req.status === 'confirmed' ? <><CheckCircle2 size={10} className="mr-1"/> Confirmado</> : <><Loader2 size={10} className="mr-1 animate-spin"/> Processando</>}
                    </span>
                    <span className="text-slate-300 text-[10px] font-bold uppercase">Criado em: {format(new Date(req.id ? parseInt(req.id.substring(0, 8), 16) * 1000 : Date.now()), 'dd/MM HH:mm')}</span>
                  </div>

                  <div className="flex flex-col md:flex-row md:items-center gap-4">
                    <div className="flex items-center text-slate-800 font-bold text-lg">
                      <Clock size={18} className="mr-2 text-[#800000]" />
                      {format(req.date, 'dd/MM/yyyy')} às {req.slot.start}
                    </div>
                    <div className="flex items-center text-slate-600 text-sm font-semibold">
                      <Building2 size={16} className="mr-1.5 opacity-50" />
                      {req.institutionName}
                    </div>
                  </div>

                  <div className="grid grid-cols-1 sm:grid-cols-3 gap-4 text-xs font-medium text-slate-500">
                     <div className="flex items-center"><User size={14} className="mr-1 opacity-50" /> {req.responsibleName}</div>
                     <div className="flex items-center"><Mail size={14} className="mr-1 opacity-50" /> {req.email}</div>
                     <div className="flex items-center"><Users size={14} className="mr-1 opacity-50" /> {req.quantity} pessoas</div>
                  </div>
                </div>

                <div className="flex items-center gap-2">
                  <button
                    onClick={() => handleDelete(req)}
                    disabled={deletingId === req.id}
                    className="p-3 text-slate-300 hover:text-red-600 hover:bg-red-50 rounded-xl transition-all"
                    title="Remover Registro"
                  >
                    {deletingId === req.id ? <Loader2 size={20} className="animate-spin" /> : <Trash2 size={20} />}
                  </button>
                  <div className="h-10 w-10 flex items-center justify-center rounded-lg bg-slate-50 text-slate-200 group-hover:text-slate-400">
                     <ChevronRight size={20} />
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </main>
    </div>
  );
};

