import React, { useState } from 'react';
import { format } from 'date-fns';
import { ptBR } from 'date-fns/locale';
import { X, Clock, Users, Building2, User, Mail, FileText, Sparkles, CheckCircle2, Loader2, ShieldCheck, MailCheck } from 'lucide-react';
import { TIME_SLOTS, TURMAS } from '../constants';
import { TimeSlot, Turma, BookingData } from '../types';
import { generateObjectiveSuggestion } from '../services/geminiService';
import { supabase } from '../services/supabase';

interface BookingDialogProps {
  date: Date;
  existingBookings: BookingData[];
  onClose: () => void;
  onComplete: (data: BookingData) => void;
}

const BookingDialog: React.FC<BookingDialogProps> = ({ date, existingBookings, onClose, onComplete }) => {
  const [step, setStep] = useState<'slot' | 'form' | 'success'>('slot');
  const [selectedSlot, setSelectedSlot] = useState<TimeSlot | null>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [formData, setFormData] = useState({
    responsibleName: '',
    institutionName: '',
    email: '',
    turma: Turma.INFANTIL,
    quantity: '' as unknown as number,
    objective: ''
  });
  const [isGenerating, setIsGenerating] = useState(false);

  const isSlotTaken = (slot: TimeSlot) => {
    const targetDateString = format(date, 'yyyy-MM-dd');
    return existingBookings.some(b => {
      const bookingDateStr = (b as any).dateString || (b.date instanceof Date ? format(b.date, 'yyyy-MM-dd') : b.date);
      return bookingDateStr === targetDateString && 
             b.slot.start === slot.start && 
             b.slot.end === slot.end &&
             b.status === 'confirmed'; 
    });
  };

  const handleSlotSelect = (slot: TimeSlot) => {
    if (isSlotTaken(slot)) return;
    setSelectedSlot(slot);
    setStep('form');
  };

  const handleSuggestObjective = async () => {
    if (!formData.institutionName) {
      alert("Por favor, informe o nome da instituição primeiro.");
      return;
    }
    setIsGenerating(true);
    const suggestion = await generateObjectiveSuggestion(formData.turma, formData.institutionName);
    setFormData(prev => ({ ...prev, objective: suggestion }));
    setIsGenerating(false);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedSlot) return;

    setIsSubmitting(true);
    try {
      const payload = {
        date: format(date, 'yyyy-MM-dd'),
        slot_start: selectedSlot.start,
        slot_end: selectedSlot.end,
        responsible_name: formData.responsibleName,
        institution_name: formData.institutionName,
        email: formData.email,
        turma: formData.turma,
        quantity: Number(formData.quantity),
        objective: formData.objective,
        status: 'pending' // O gatilho no banco mudará para 'confirmed' após o envio do e-mail
      };

      const { error: dbError } = await supabase.from('bookings').insert([payload]);
      if (dbError) throw dbError;

      onComplete({
        date,
        slot: selectedSlot,
        ...formData,
        quantity: Number(formData.quantity),
        status: 'pending'
      });
      setStep('success');
    } catch (e: any) {
      console.error("Erro geral:", e);
      alert(`Erro: ${e.message || "Falha ao processar solicitação."}`);
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-900/70 backdrop-blur-md">
      <div className={`bg-white w-full max-w-2xl rounded-2xl shadow-2xl overflow-hidden max-h-[95vh] flex flex-col transition-all duration-300`}>

        {step !== 'success' && (
          <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-white sticky top-0 z-10">
            <div>
              <h3 className="text-xl font-bold text-slate-800">
                Agendamento para {format(date, "dd 'de' MMMM", { locale: ptBR })}
              </h3>
            </div>
            <button onClick={onClose} className="p-2 hover:bg-slate-100 rounded-full transition-colors text-slate-400">
              <X size={24} />
            </button>
          </div>
        )}

        <div className="overflow-y-auto">
          {step === 'slot' && (
            <div className="p-6 space-y-4">
              <h4 className="text-lg font-semibold text-slate-700 mb-4 text-center">Escolha o Horário</h4>
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                {TIME_SLOTS.map((slot, idx) => {
                  const occupied = isSlotTaken(slot);
                  return (
                    <button
                      key={idx}
                      disabled={occupied}
                      onClick={() => handleSlotSelect(slot)}
                      className={`flex items-center justify-between p-4 border rounded-xl transition-all ${occupied ? 'bg-red-50 border-red-100 opacity-90' : 'border-slate-200 hover:border-[#800000] hover:bg-red-50'}`}
                    >
                      <span className="font-semibold">{slot.start} - {slot.end}</span>
                      <span className={`text-[10px] font-bold uppercase ${occupied ? 'text-red-600' : 'text-green-500'}`}>{occupied ? 'Ocupado' : 'Disponível'}</span>
                    </button>
                  );
                })}
              </div>
            </div>
          )}

          {step === 'form' && (
            <form onSubmit={handleSubmit} className="p-6 space-y-6">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <div className="space-y-1">
                  <label className="text-xs font-bold text-slate-500 uppercase tracking-wider flex items-center"><User size={12} className="mr-1" /> Responsável</label>
                  <input required disabled={isSubmitting} type="text" value={formData.responsibleName} onChange={e => setFormData(prev => ({ ...prev, responsibleName: e.target.value }))} className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-[#800000] outline-none" />
                </div>
                <div className="space-y-1">
                  <label className="text-xs font-bold text-slate-500 uppercase tracking-wider flex items-center"><Building2 size={12} className="mr-1" /> Instituição</label>
                  <input required disabled={isSubmitting} type="text" value={formData.institutionName} onChange={e => setFormData(prev => ({ ...prev, institutionName: e.target.value }))} className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-[#800000] outline-none" />
                </div>
                <div className="space-y-1">
                  <label className="text-xs font-bold text-slate-500 uppercase tracking-wider flex items-center"><Mail size={12} className="mr-1" /> E-mail para Confirmação</label>
                  <input required disabled={isSubmitting} type="email" value={formData.email} onChange={e => setFormData(prev => ({ ...prev, email: e.target.value }))} className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-[#800000] outline-none" />
                </div>
                <div className="space-y-1">
                  <label className="text-xs font-bold text-slate-500 uppercase tracking-wider flex items-center"><Users size={12} className="mr-1" /> Pessoas (Máx: 40)</label>
                  <input required disabled={isSubmitting} type="number" max="40" value={formData.quantity} onChange={e => setFormData(prev => ({ ...prev, quantity: e.target.value as any }))} className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-[#800000] outline-none" />
                </div>
              </div>
              <div className="space-y-1">
                <div className="flex justify-between items-center mb-1">
                   <label className="text-xs font-bold text-slate-500 uppercase tracking-wider flex items-center"><FileText size={12} className="mr-1" /> Objetivo da Visita</label>
                   <button type="button" onClick={handleSuggestObjective} className="text-[10px] font-bold text-[#800000] bg-red-50 px-2 py-1 rounded-md border border-red-100 flex items-center">
                     {isGenerating ? <Loader2 size={10} className="animate-spin mr-1" /> : <Sparkles size={10} className="mr-1" />} 
                     Gerar Objetivo com IA
                   </button>
                </div>
                <textarea required disabled={isSubmitting} rows={3} value={formData.objective} onChange={e => setFormData(prev => ({ ...prev, objective: e.target.value }))} className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-[#800000] outline-none resize-none text-sm" />
              </div>
              <button type="submit" disabled={isSubmitting} className="w-full py-4 bg-[#800000] text-white font-bold rounded-xl flex items-center justify-center disabled:bg-slate-400 shadow-lg shadow-red-900/20 active:scale-95 transition-all">
                {isSubmitting ? <><Loader2 className="animate-spin mr-2" size={20} /> Finalizando...</> : 'Confirmar Agendamento'}
              </button>
            </form>
          )}

          {step === 'success' && (
            <div className="flex flex-col bg-white min-h-full animate-in fade-in zoom-in duration-500">
              <div className="bg-green-600 p-10 text-center">
                <div className="w-16 h-16 bg-white rounded-full flex items-center justify-center mx-auto mb-4 shadow-xl"><MailCheck size={36} className="text-green-600" /></div>
                <h2 className="text-2xl font-black text-white uppercase tracking-tight">Agendamento Realizado!</h2>
              </div>

              <div className="p-8 space-y-6 flex flex-col items-center text-center">
                <div className="bg-green-50 border-2 border-green-100 p-6 rounded-3xl w-full max-w-md">
                   <h4 className="text-green-800 font-bold uppercase text-sm mb-2 tracking-widest">Confirmação Instantânea</h4>
                   <p className="text-green-700 text-sm leading-relaxed font-medium">
                     Um e-mail oficial contendo todos os detalhes da visita, regras da biblioteca e confirmação de horário acaba de ser enviado para <strong>{formData.email}</strong>.
                   </p>
                </div>

                <div className="flex items-center space-x-2 text-slate-400">
                   <ShieldCheck size={16} />
                   <p className="text-[10px] font-bold uppercase tracking-widest">Sistema de Agendamento Automático da Biblioteca</p>
                </div>

                <button onClick={onClose} className="bg-slate-900 text-white px-12 py-4 rounded-2xl font-black uppercase tracking-widest text-xs hover:bg-slate-800 active:scale-95 transition-all shadow-xl">
                  Concluir
                </button>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default BookingDialog;

import React, { useState } from 'react';
import { format } from 'date-fns';
