                    >
                      <span className="font-semibold">{slot.start} - {slot.end}</span>
                      <span className={`text-[10px] font-bold uppercase ${occupied ? 'text-red-600' : 'text-green-500'}`}>{occupied ? 'Ocupado' : 'Disponível'}</span>
