                  <input required disabled={isSubmitting} type="email" value={formData.email} onChange={e => setFormData(prev => ({ ...prev, email: e.target.value }))} className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-[#800000] outline-none" />
                </div>
                <div className="space-y-1">
                  <label className="text-xs font-bold text-slate-500 uppercase tracking-wider flex items-center"><Users size={12} className="mr-1" /> Pessoas (Máx: 40)</label>
                  <input required disabled={isSubmitting} type="number" max="40" value={formData.quantity} onChange={e => setFormData(prev => ({ ...prev, quantity: e.target.value as any }))} className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-[#800000] outline-none" />
                </div>
              </div>
              <div className="space-y-1">
                <div className="flex justify-between items-center mb-1">
                   <label className="text-xs font-bold text-slate-500 uppercase tracking-wider flex items-center"><FileText size={12} className="mr-1" /> Objetivo da Visita</label>
                   <button type="button" onClick={handleSuggestObjective} className="text-[10px] font-bold text-[#800000] bg-red-50 px-2 py-1 rounded-md border border-red-100 flex items-center">
