                <h2 className="text-2xl font-black text-white uppercase tracking-tight">Agendamento Realizado!</h2>
              </div>

              <div className="p-8 space-y-6 flex flex-col items-center text-center">
                <div className="bg-green-50 border-2 border-green-100 p-6 rounded-3xl w-full max-w-md">
