  const [adminPassword, setAdminPassword] = useState('');
  const [selectedDate, setSelectedDate] = useState<Date | null>(null);
  const [showDialog, setShowDialog] = useState(false);
  const [allBookings, setAllBookings] = useState<BookingData[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  const fetchBookings = async () => {
    setIsLoading(true);
    setError(null);
    try {
      const { data, error: supabaseError } = await supabase
        .from('bookings')
        .select('*');

      if (supabaseError) throw supabaseError;

      if (data) {
        const formatted = data.map((b: any) => ({
          ...b,
          dateString: b.date, 
          date: new Date(b.date + 'T12:00:00'),
          slot: { start: b.slot_start, end: b.slot_end },
          responsibleName: b.responsible_name,
          institutionName: b.institution_name,
        }));
        setAllBookings(formatted);
      }
    } catch (e: any) {
      console.error("Erro Supabase:", e);
      const msg = e.message || (typeof e === 'string' ? e : "Erro de conexão com o banco de dados.");
      setError(msg);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    fetchBookings();
  }, []);

  const handleAdminLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (adminPassword === 'biblioteca2024') {
      setView('admin');
      setAdminPassword('');
    } else {
      alert("Senha administrativa incorreta.");
    }
  };

  if (view === 'admin') {
    return <AdminDashboard onLogout={() => setView('public')} />;
  }

  if (view === 'admin-login') {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center p-4">
        <div className="bg-white w-full max-w-md p-10 rounded-3xl shadow-2xl space-y-8 animate-in zoom-in duration-300">
           <div className="text-center space-y-2">
             <div className="bg-[#800000] w-16 h-16 rounded-2xl flex items-center justify-center mx-auto text-white shadow-xl shadow-red-900/30">
               <Lock size={32} />
             </div>
             <h2 className="text-2xl font-black text-slate-800 uppercase tracking-tighter pt-4">Área Restrita</h2>
             <p className="text-slate-400 text-sm font-medium">Somente para equipe da Biblioteca</p>
           </div>

           <form onSubmit={handleAdminLogin} className="space-y-4">
             <div className="space-y-1">
               <label className="text-xs font-bold text-slate-500 uppercase tracking-widest">Senha de Acesso</label>
               <input 
                 autoFocus
                 type="password" 
                 value={adminPassword} 
                 onChange={e => setAdminPassword(e.target.value)}
                 className="w-full px-5 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl focus:border-[#800000] outline-none transition-all text-center text-xl font-bold tracking-widest"
                 placeholder="••••••••"
               />
             </div>
             <button type="submit" className="w-full bg-[#800000] text-white py-4 rounded-2xl font-black uppercase tracking-widest hover:bg-[#600000] transition-all shadow-lg active:scale-95">
               Entrar no Painel
             </button>
             <button type="button" onClick={() => setView('public')} className="w-full text-slate-400 font-bold text-xs uppercase tracking-widest py-2">
               Voltar ao Calendário
             </button>
           </form>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      <header className="bg-white border-b border-slate-200 sticky top-0 z-40">
        <div className="max-w-7xl mx-auto px-4 h-20 flex items-center justify-between">
          <div className="flex items-center space-x-3">
            <div className="bg-[#800000] p-2.5 rounded-lg shadow-md shadow-red-900/20">
              <BookOpen className="text-white" size={24} />
            </div>
            <div className="flex flex-col">
              <h1 className="text-lg font-bold text-[#800000] tracking-tight leading-none uppercase">Biblioteca Municipal de Sobral</h1>
              <span className="text-xs font-medium text-slate-500 uppercase tracking-widest">Lustosa da Costa</span>
            </div>
          </div>
          <button 
            onClick={() => setView('admin-login')}
            className="flex items-center space-x-2 text-xs font-bold text-slate-400 uppercase tracking-widest hover:text-[#800000] transition-colors"
          >
            <Lock size={14} /> <span>Acesso Equipe</span>
