import React, { useState, useEffect } from 'react';
import { supabase } from '../services/supabase';
import { BookingData } from '../types';
import { format, parseISO } from 'date-fns';
import { ptBR } from 'date-fns/locale';
import { 
  CheckCircle2, 
  Clock, 
  Search, 
  User, 
  Mail, 
  Building2, 
  Users, 
  ChevronRight, 
  Loader2, 
  LogOut, 
  ShieldCheck,
  Trash2,
  RefreshCcw,
  Zap,
  AlertTriangle,
  Calendar as CalendarIcon
} from 'lucide-react';

const AdminDashboard: React.FC<{ onLogout: () => void }> = ({ onLogout }) => {
  const [requests, setRequests] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState<'all' | 'pending' | 'confirmed'>('all');
  const [deletingId, setDeletingId] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);

  const fetchRequests = async () => {
    setLoading(true);
    setError(null);
    try {
      const { data, error: dbError } = await supabase
        .from('bookings')
        .select('*')
        .order('created_at', { ascending: false });

      if (dbError) throw dbError;

      if (data) {
        const formatted = data.map((b: any) => ({
          ...b,
          // Segurança na conversão de data
          jsDate: b.date ? new Date(b.date + 'T12:00:00') : new Date(),
          slot: { start: b.slot_start || '00:00', end: b.slot_end || '00:00' },
          responsibleName: b.responsible_name || 'Não informado',
          institutionName: b.institution_name || 'Instituição não informada',
        }));
        setRequests(formatted);
      }
    } catch (e: any) {
      console.error("Erro ao carregar solicitações:", e);
      setError(e.message || "Erro ao conectar com o banco de dados.");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchRequests();
  }, []);

  const handleDelete = async (req: any) => {
    if (!req.id) return;
    const confirmDelete = window.confirm(`Excluir permanentemente o registro de ${req.institutionName}?`);
    if (!confirmDelete) return;

    setDeletingId(req.id);
    try {
      const { error: delError } = await supabase.from('bookings').delete().eq('id', req.id);
      if (delError) throw delError;
      setRequests(prev => prev.filter(r => r.id !== req.id));
    } catch (e: any) {
      alert("Erro ao excluir: " + e.message);
    } finally {
      setDeletingId(null);
    }
  };

  const filteredRequests = requests.filter(r => {
    if (filter === 'all') return true;
    return r.status === filter;
  });

  const formatDateSafely = (dateStr: string) => {
    try {
      if (!dateStr) return "Data indisponível";
      return format(parseISO(dateStr), "dd/MM 'às' HH:mm", { locale: ptBR });
    } catch (e) {
      return "Data indisponível";
    }
  };

  return (
    <div className="min-h-screen bg-slate-100/80">
      {/* Header com mais contraste */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-50 px-8 h-20 flex items-center justify-between shadow-sm">
        <div className="flex items-center space-x-4">
          <div className="bg-[#800000] p-2 rounded-xl text-white shadow-lg shadow-red-900/20 rotate-3">
            <ShieldCheck size={24} />
          </div>
          <div>
            <h1 className="font-black text-slate-900 uppercase tracking-tighter text-base leading-none">Painel de Controle</h1>
            <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-1">Gestão de Visitas Guiadas</p>
          </div>
        </div>

        <div className="flex items-center space-x-6">
          <button 
            onClick={fetchRequests} 
            className="flex items-center space-x-2 text-slate-500 hover:text-[#800000] transition-colors group"
          >
             <span className="text-[10px] font-bold uppercase tracking-widest opacity-0 group-hover:opacity-100 transition-all">Atualizar</span>
             <RefreshCcw size={18} className={loading ? 'animate-spin' : ''} />
          </button>
          <div className="h-8 w-px bg-slate-200"></div>
          <button 
            onClick={onLogout} 
            className="bg-slate-900 text-white px-5 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest hover:bg-red-700 transition-all flex items-center"
          >
            <LogOut size={14} className="mr-2" /> Sair
          </button>
        </div>
      </header>

      <main className="max-w-6xl mx-auto p-8 space-y-8">
        {/* Banner de Status da Automação */}
        <div className="bg-gradient-to-r from-[#800000] to-red-900 rounded-[2rem] p-8 text-white shadow-2xl shadow-red-900/20 flex flex-col md:flex-row items-center justify-between gap-6 overflow-hidden relative">
           <div className="absolute top-0 right-0 w-64 h-64 bg-white/5 rounded-full -mr-32 -mt-32 blur-3xl"></div>
           <div className="relative z-10 space-y-2 text-center md:text-left">
             <div className="flex items-center justify-center md:justify-start space-x-2">
                <span className="bg-green-500 w-2 h-2 rounded-full animate-pulse"></span>
                <h2 className="text-xl font-black uppercase tracking-tight">Monitor de Automação</h2>
             </div>
             <p className="text-red-100/70 text-sm font-medium max-w-md">O sistema confirma agendamentos e envia e-mails automaticamente. Não é necessária intervenção manual para confirmação.</p>
           </div>

           <div className="relative z-10 flex items-center space-x-8">
              <div className="text-center">
                <p className="text-4xl font-black">{requests.filter(r => r.status === 'confirmed').length}</p>
                <p className="text-[10px] font-bold uppercase text-red-200 tracking-widest">Confirmados</p>
              </div>
              <div className="h-12 w-px bg-white/20"></div>
              <div className="text-center">
                <p className="text-4xl font-black">{requests.length}</p>
                <p className="text-[10px] font-bold uppercase text-red-200 tracking-widest">Total Geral</p>
              </div>
           </div>
        </div>

        {/* Filtros */}
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 bg-white p-4 rounded-3xl shadow-sm border border-slate-200">
          <div className="flex bg-slate-100 p-1 rounded-2xl w-fit">
            {(['all', 'confirmed', 'pending'] as const).map(f => (
              <button
                key={f}
                onClick={() => setFilter(f)}
                className={`px-6 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${filter === f ? 'bg-white text-slate-900 shadow-md' : 'text-slate-400 hover:text-slate-600'}`}
              >
                {f === 'all' ? 'Ver Todos' : f === 'confirmed' ? 'Confirmados' : 'Processando'}
              </button>
            ))}
          </div>
          <div className="flex items-center text-slate-400 text-[10px] font-bold uppercase tracking-widest px-4">
             <Search size={14} className="mr-2" /> Pesquisar por instituição...
          </div>
        </div>

        {/* Listagem com Tratamento de Erro */}
        {error ? (
          <div className="bg-white border-2 border-red-100 rounded-[2.5rem] p-12 text-center space-y-4">
             <AlertTriangle size={48} className="text-red-600 mx-auto" />
             <h3 className="text-xl font-black text-slate-800 uppercase">Falha na Conexão</h3>
             <p className="text-slate-500 max-w-sm mx-auto">{error}</p>
             <button onClick={fetchRequests} className="bg-[#800000] text-white px-8 py-3 rounded-xl font-bold uppercase text-xs">Tentar Novamente</button>
          </div>
        ) : loading && requests.length === 0 ? (
          <div className="flex flex-col items-center justify-center py-20 text-slate-400">
            <Loader2 className="animate-spin mb-4" size={48} />
            <p className="font-black uppercase tracking-widest text-[10px]">Lendo base de dados...</p>
          </div>
        ) : filteredRequests.length === 0 ? (
          <div className="bg-white border-2 border-dashed border-slate-200 rounded-[2.5rem] py-24 flex flex-col items-center justify-center text-slate-400">
             <Search size={64} className="mb-6 opacity-10" />
             <p className="font-bold uppercase tracking-widest text-xs">Nenhum registro para exibir</p>
          </div>
        ) : (
          <div className="grid grid-cols-1 gap-6">
            {filteredRequests.map((req) => (
              <div 
                key={req.id} 
                className="bg-white border border-slate-200 rounded-[2rem] p-6 hover:shadow-xl hover:shadow-slate-200/50 hover:border-slate-300 transition-all flex flex-col md:flex-row md:items-center justify-between gap-8 group relative overflow-hidden"
              >
                {/* Indicador Lateral de Status */}
                <div className={`absolute left-0 top-0 bottom-0 w-2 ${req.status === 'confirmed' ? 'bg-green-500' : 'bg-blue-500'}`}></div>

                <div className="space-y-4 flex-grow">
                  <div className="flex items-center space-x-3">
                    <span className={`px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-widest flex items-center ${req.status === 'confirmed' ? 'bg-green-50 text-green-700' : 'bg-blue-50 text-blue-700'}`}>
                      {req.status === 'confirmed' ? <><CheckCircle2 size={10} className="mr-1"/> Confirmado</> : <><Loader2 size={10} className="mr-1 animate-spin"/> Processando</>}
                    </span>
                    <span className="text-slate-300 text-[9px] font-black uppercase tracking-widest">
                      ID: {req.id ? String(req.id).substring(0, 8) : '---'} • Solicitado em {formatDateSafely(req.created_at)}
                    </span>
                  </div>

                  <div className="flex flex-col md:flex-row md:items-center gap-6">
                    <div className="flex items-center text-slate-900 font-black text-xl tracking-tighter">
                      <CalendarIcon size={20} className="mr-3 text-[#800000]" />
                      {format(req.jsDate, 'dd/MM/yyyy')} 
                      <span className="mx-2 text-slate-300 font-light">—</span>
                      <span className="text-[#800000]">{req.slot.start}</span>
                    </div>
                    <div className="flex items-center text-slate-700 font-bold bg-slate-50 px-4 py-2 rounded-xl border border-slate-100">
                      <Building2 size={18} className="mr-3 text-slate-400" />
                      {req.institutionName}
                    </div>
                  </div>

                  <div className="grid grid-cols-1 sm:grid-cols-3 gap-6 text-xs font-bold text-slate-500 uppercase tracking-widest">
                     <div className="flex items-center"><User size={14} className="mr-2 text-slate-300" /> {req.responsibleName}</div>
                     <div className="flex items-center"><Mail size={14} className="mr-2 text-slate-300" /> {req.email}</div>
                     <div className="flex items-center"><Users size={14} className="mr-2 text-slate-300" /> {req.quantity} pessoas</div>
                  </div>

                  <div className="bg-slate-50/50 p-4 rounded-2xl border border-slate-100 mt-2">
                     <p className="text-[9px] text-slate-400 uppercase mb-1">Objetivo Pedagógico</p>
                     <p className="text-xs text-slate-600 font-medium italic">"{req.objective || 'Nenhum objetivo descrito.'}"</p>
                  </div>
                </div>

                <div className="flex items-center gap-3">
                  <button
                    onClick={() => handleDelete(req)}
                    disabled={deletingId === req.id}
                    className="p-4 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-2xl transition-all flex flex-col items-center justify-center space-y-1"
                    title="Excluir Registro"
                  >
                    {deletingId === req.id ? <Loader2 size={20} className="animate-spin" /> : <Trash2 size={20} />}
                    <span className="text-[8px] font-black uppercase">Excluir</span>
                  </button>
                  <div className="h-12 w-12 flex items-center justify-center rounded-2xl bg-slate-100 text-slate-400 group-hover:bg-[#800000] group-hover:text-white transition-all shadow-inner">
                     <ChevronRight size={24} />
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </main>

      {/* Footer do Painel */}
      <footer className="max-w-6xl mx-auto p-12 text-center">
         <div className="inline-flex items-center space-x-2 text-slate-300">
            <ShieldCheck size={16} />
            <span className="text-[10px] font-black uppercase tracking-[0.2em]">Área de Acesso Restrito • Gestão Biblioteca de Sobral</span>
         </div>
      </footer>
    </div>
  );
};

export default AdminDashboard;
